import { useContext, useReducer } from "react";
import { QuizContext, QuizDispatchContext } from "./QuizContext";

import commonReducer from "../../features/commonReducer";

import useSaveRealtimeDb from './useSaveRealtimeDb';

import { useDispatch } from "react-redux";
import { upsertPost } from "../../features/posts/postsSlice";
//import MathText from "../OLdMathQuizCard/MathText";
import ProcessKatex from "./ProcessKatex";

import { Form, Button } from "react-bootstrap";

import arraysEqual from "../../utilities/arraysEqual";


function ContextMultipleChoicesQuiz() {
        const globalDispatch = useDispatch();
    const { saveData, loading, error } = useSaveRealtimeDb();
    const { choices, answers, id, isAnswered, isExam } = useContext(QuizContext)
    const dispatch = useContext(QuizDispatchContext);

    const [localState, localDispatch] = useReducer(
        commonReducer, { selectedAnswers: [] }
    );



    function handleCheckboxChange(item, isChecked) {
        // console.log(item, isChecked);
        if (isChecked) {

            localDispatch({
                type: "PUSH_ITEM_TO_ARRAY",
                payload: {
                    arrayName: "selectedAnswers",
                    item: item
                },
            })


            dispatch({
                type: "PUSH_ITEM_TO_ARRAY",
                payload: {
                    arrayName: "selectedAnswers",
                    item: item
                },
            })


        } else {

            localDispatch({
                type: "DELETE_ITEM_FROM_FLAT_ARRAY",
                payload: {
                    arrayName: "selectedAnswers",
                    item: item
                },
            })

            dispatch({
                type: "DELETE_ITEM_FROM_FLAT_ARRAY",
                payload: {
                    arrayName: "selectedAnswers",
                    item: item
                },
            })
        }
    }

    const handleSubmit = async (event) => {
        event.preventDefault();
     //   console.log("Summited")

      if (isExam) {
                 console.log(id)
                 globalDispatch(
                     upsertPost({
                         quizId: id,
                         id: id,
                         timestamp: Date.now(),
                         userValue: localState.selectedAnswers.length > 0 ? localState.selectedAnswers : [] ,                      
                     }))
             }



        if (arraysEqual(answers, localState.selectedAnswers)) {

            dispatch({
                type: "SEED_STATE",
                payload: {
                    objects: {
                        isAnswered: true,
                        isCorrect: true,
                    },
                },
            });

            await saveData(localState.selectedAnswers.join("; "));

        } else {
            dispatch({
                type: "SEED_STATE",
                payload: {
                    objects: {
                        isAnswered: true,
                        isCorrect: false,
                    },
                },
            });
        }
    }


    return <Form onSubmit={handleSubmit} key={id}>

        <Form.Group controlId={"formBasicCheckbox"}>
            {choices.map((item, index) =>
                <Form.Check
                    key={index}
                    type='checkbox' // Изменено с radio на checkbox
                    label={<ProcessKatex
                        text={item}
                        className="card-text m-1 math-text"
                    />}
                    onChange={(e) => handleCheckboxChange(item, e.target.checked)}
                    name={"answers"} // Можно оставить одно имя для группы
                    id={`answer-${index}`}
                    value={item}
                    checked={localState.selectedAnswers.includes(item)} // Контролируемый компонент
                    className="mb-2"
                />
            )}
        </Form.Group>

        <Button variant="outline-secondary" size="sm" type="submit" disabled={isAnswered}>
            Ответ
        </Button>

         {loading ? <span>...</span> : error ? <span>{":-("}</span> : null}

    </Form>





}

export default ContextMultipleChoicesQuiz