import React, { useEffect, useRef } from 'react';
//import JXG from 'jsxgraph';

const Cone3D = () => {
  const boardRef = useRef(null);

  useEffect(() => {
    const board = JXG.JSXGraph.initBoard(boardRef.current, {
      boundingbox: [-3, 4, 5, -1],
      axis: true,
      grid: true,
      showNavigation: false,
      showCopyright: false
    });

    // Центр основания
    const O = board.create('point', [0, 0], { name: 'O', size: 4, color: 'blue' });
    
    // Вершина конуса
    const S = board.create('point', [0, 3], { name: 'S', size: 4, color: 'red' });
    
    // Основание - окружность
    const circle = board.create('circle', [O, 2], {
      strokeColor: 'blue',
      strokeWidth: 2,
      fillColor: 'lightblue',
      fillOpacity: 0.2
    });

    // Образующие
    const A = board.create('point', [2, 0], { name: 'A', size: 3, color: 'blue' });
    const B = board.create('point', [-2, 0], { name: 'B', size: 3, color: 'blue' });
    
    board.create('segment', [A, S], {
      strokeColor: 'red',
      strokeWidth: 2
    });
    
    board.create('segment', [B, S], {
      strokeColor: 'red',
      strokeWidth: 2
    });

    // Высота
    board.create('segment', [O, S], {
      strokeColor: 'green',
      strokeWidth: 2,
      dash: 2
    });

    // Образующая l (наклонная)
    board.create('segment', [A, S], {
      strokeColor: 'orange',
      strokeWidth: 2
    });

    // Подписи
    board.create('text', [1, 1.5, 'l = √13 ≈ 3.61'], { fontSize: 12, color: 'darkorange' });
    board.create('text', [0.3, 1.5, 'h = 3'], { fontSize: 12, color: 'darkgreen' });
    board.create('text', [0, -0.3, 'R = 2'], { fontSize: 12, color: 'darkblue' });

    // Формулы
    board.create('text', [-2.8, 3.8, 'V = ⅓πR²h = ⅓π·4·3 = 4π'], {
      fontSize: 14,
      color: 'darkgreen',
      anchorX: 'left'
    });

    return () => board.unsuspendUpdate();
  }, []);

  return (
    <div>
      <h4>Конус: R = 2, h = 3, l = √13 ≈ 3.61</h4>
      <div ref={boardRef} style={{ width: '100%', height: '500px' }} />
    </div>
  );
};

export default Cone3D;