import React, {useState, useEffect} from "react";

import katex from 'katex';


export function makeHTMLFromKatex(expression, displayMode = false) {
    return katex.renderToString(expression, {
                displayMode: displayMode,
                throwOnError: false,
                output: 'html',
                strict: false
            })
}

// Компонент для отображения KaTeX формул
const MathExpression = ({ expression, displayMode = false, className = "" }) => {
    const [html, setHtml] = useState('');

    useEffect(() => {
        try {
            const katexHtml = makeHTMLFromKatex(expression, displayMode)
            setHtml(katexHtml);
        } catch (error) {
            console.error('KaTeX rendering error:', error);
            setHtml(`<span class="text-danger">${expression}</span>`);
        }
    }, [expression, displayMode]);

    return <span className={className} dangerouslySetInnerHTML={{ __html: html }} />;
};

export function processTextWithFormulas (inputText) {
   // console.log(inputText);
        if (!inputText) return null;
        
        const parts = inputText.split(/(\$[^$]+\$)/g);

    //    console.log(parts);
        
        return parts.map((part, index) => {
            if (part.startsWith('$') && part.endsWith('$')) {
                const formula = part.slice(1, -1);
                return <MathExpression key={index} expression={formula} />;
            } else {
                if (part.includes('<div>') || part.includes('<svg>') || part.includes('<p>')) {
                    return <div key={index} dangerouslySetInnerHTML={{ __html: part }} />;
                }
                return <span key={index}>{part}</span>;
            }
        });
    };

// Компонент для отображения математического текста с формулами
const MathText = ({ text, className = "" }) => {
    return <div className={className}>{processTextWithFormulas(text)}</div>;
};


// Вспомогательная функция для добавления классов Bootstrap (только вне SVG)
const getBootstrapClasses = (tagName, node) => {
    const classes = [];
    
    switch (tagName) {
        case 'h1':
        case 'h2':
        case 'h3':
        case 'h4':
        case 'h5':
        case 'h6':
            classes.push('mb-3 mt-4');
            break;
        case 'p':
            classes.push('mb-3');
            break;
        case 'ul':
        case 'ol':
            classes.push('mb-3 pl-3');
            break;
        case 'li':
            classes.push('mb-1');
            break;
        case 'blockquote':
            classes.push('blockquote pl-3 ml-3 text-muted');
            break;
        case 'code':
            if (!node.closest('pre')) {
                classes.push('badge badge-secondary p-1');
            }
            break;
        case 'pre':
            classes.push('bg-dark text-light p-3 rounded mb-3');
            break;
        case 'hr':
            classes.push('my-4');
            break;
        case 'div':
            // Проверяем, не является ли div контейнером для формулы
            if (!node.textContent.includes('$$')) {
                classes.push('mb-2');
            }
            break;
        case 'span':
            // Не добавляем классы для обычных span
            break;
        default:
            if (!['path', 'circle', 'rect', 'g', 'svg'].includes(tagName)) {
                classes.push('mb-2');
            }
    }

    // Сохраняем оригинальные классы
    const originalClass = node.getAttribute('class');
    if (originalClass) {
        classes.push(originalClass);
    }

    return classes.join(' ');
};

// Функция для сохранения оригинальных классов (в основном для SVG)
const getOriginalClasses = (node) => {
    return node.getAttribute('class') || '';
};

const MixedContent = ({ content, className = "" }) => {
    const processContent = (text) => {
        if (!text) return null;

        const tempDiv = document.createElement('div');
        tempDiv.innerHTML = text;

        const processNode = (node, key) => {
            // Если это SVG или его дочерний элемент, сохраняем как есть
            if (node.nodeType === Node.ELEMENT_NODE && 
                (node.tagName.toLowerCase() === 'svg' || node.closest('svg'))) {
                return (
                    <span 
                        key={key}
                        dangerouslySetInnerHTML={{ __html: node.outerHTML }} 
                    />
                );
            }

            if (node.nodeType === Node.TEXT_NODE) {
                const parts = node.textContent.split(/(\$\$[^$]+\$\$)/g);
                
                if (parts.length > 1) {
                    const elements = [];
                    
                    parts.forEach((part, partIndex) => {
                        if (part.startsWith('$$') && part.endsWith('$$')) {
                            const formula = part.slice(2, -2);
                            elements.push(
                                <div key={`${key}-formula-${partIndex}`} className="text-center my-3 p-2 bg-light rounded">
                                    <MathExpression expression={formula} displayMode={true} />
                                </div>
                            );
                        } else if (part.trim() !== '') {
                            elements.push(
                                <span key={`${key}-text-${partIndex}`}>{part}</span>
                            );
                        }
                    });
                    
                    return elements;
                } else if (node.textContent.trim() !== '') {
                    return <span key={key}>{node.textContent}</span>;
                }
            } else if (node.nodeType === Node.ELEMENT_NODE) {
                const tagName = node.tagName.toLowerCase();
                const props = { 
                    key: `${key}-${tagName}`,
                    className: getBootstrapClasses(tagName, node)
                };

                // Обрабатываем дочерние элементы
                const children = [];
                node.childNodes.forEach((child, childIndex) => {
                    const processedChild = processNode(child, `${key}-child-${childIndex}`);
                    if (processedChild) {
                        if (Array.isArray(processedChild)) {
                            children.push(...processedChild);
                        } else {
                            children.push(processedChild);
                        }
                    }
                });

                // Копируем атрибуты
                Array.from(node.attributes).forEach(attr => {
                    if (attr.name !== 'class') {
                        props[attr.name] = attr.value;
                    }
                });

                return React.createElement(tagName, props, children.length > 0 ? children : null);
            }
            
            return null;
        };

        const walkDOM = (node, baseKey = '0') => {
            const children = [];
            
            node.childNodes.forEach((child, index) => {
                const processed = processNode(child, `${baseKey}-${index}`);
                if (processed) {
                    if (Array.isArray(processed)) {
                        children.push(...processed);
                    } else {
                        children.push(processed);
                    }
                }
            });
            
            return children;
        };

        return walkDOM(tempDiv);
    };

    return <div className={`${className} container-fluid`}>{processContent(content)}</div>;
};



export { MathText }

export default MixedContent 