import React, { useEffect, useRef } from 'react';
import katex from 'katex';

const ReductionFormulas = () => {
  const boardRef = useRef(null);

  useEffect(() => {
    const board = window.JXG.JSXGraph.initBoard(boardRef.current, {
      boundingbox: [-2, 2, 2, -2],
      axis: true,
      grid: true,
      showNavigation: false,
      showCopyright: false
    });

    const colors = {
      circle: '#6c757d',
      alpha: '#dc3545',
      piMinusAlpha: '#007bff',
      piPlusAlpha: '#28a745',
      minusAlpha: '#ffc107'
    };

    // Единичная окружность
    board.create('circle', [[0, 0], [1, 0]], {
      strokeColor: colors.circle,
      strokeWidth: 1,
      fillColor: 'none'
    });

    // Центр
    const O = board.create('point', [0, 0], {
      name: '', size: 2, color: '#212529', fixed: true
    });

    // Точки для разных углов
    const createAnglePoint = (angleFunc, color, label) => {
      const point = board.create('point', [
        () => Math.cos(angleFunc()),
        () => Math.sin(angleFunc())
      ], {
        name: '', size: 3, color: color, fixed: true
      });

      board.create('segment', [O, point], {
        strokeColor: color,
        strokeWidth: 1,
        dash: 1
      });

      const text = board.create('text', [
        () => Math.cos(angleFunc()) * 1.15,
        () => Math.sin(angleFunc()) * 1.15,
        label
      ], {
        color: color,
        fontSize: 12,
        fixed: true
      });

      return point;
    };

    // Слайдер для α
    const slider = board.create('slider', [[-1.5, -1.5], [1, -1.5], [0, 0, 2 * Math.PI]], {
      name: 'α',
      snapWidth: Math.PI / 12,
      baselineColor: 'gray',
      highlineColor: 'blue',
      fillColor: 'lightblue',
      strokeColor: 'blue',
      width: 8
    });

    // Угол α (основной)
    board.alpha = () => slider.Value();

    // Создаем симметричные точки
    const P_alpha = createAnglePoint(
      () => board.alpha(),
      colors.alpha,
      'α'
    );

    const P_piMinusAlpha = createAnglePoint(
      () => Math.PI - board.alpha(),
      colors.piMinusAlpha,
      'π-α'
    );

    const P_piPlusAlpha = createAnglePoint(
      () => Math.PI + board.alpha(),
      colors.piPlusAlpha,
      'π+α'
    );

    const P_minusAlpha = createAnglePoint(
      () => -board.alpha(),
      colors.minusAlpha,
      '-α'
    );

    // Показываем координаты
    const P_alpha_dot = board.create('point', [
      () => Math.cos(board.alpha()),
      () => Math.sin(board.alpha())
    ], {
      name: '', size: 3, color: colors.alpha, fixed: true
    });

    const P_piMinusAlpha_dot = board.create('point', [
      () => Math.cos(Math.PI - board.alpha()),
      () => Math.sin(Math.PI - board.alpha())
    ], {
      name: '', size: 3, color: colors.piMinusAlpha, fixed: true
    });

    // Формулы
    const formulaBox = board.create('text', [-1.8, 1.8, ''], {
      fontSize: 14,
      color: '#212529',
      fixed: true,
      parse: false
    });

    const updateFormula = () => {
      const alpha = board.alpha();
      const sinA = Math.sin(alpha);
      const sinPiMinusA = Math.sin(Math.PI - alpha);
      
      const formula = `\\sin(\\pi-\\alpha) = \\sin\\alpha = ${sinA.toFixed(2)}`;
      
      try {
        const html = katex.renderToString(formula, {
          displayMode: true,
          throwOnError: false
        });
        formulaBox.setText(html);
      } catch (error) {
        formulaBox.setText(formula);
      }
    };

    slider.on('drag', updateFormula);
    slider.on('up', updateFormula);
    updateFormula();

    // Объяснение
    const explanation = board.create('text', [-1.8, -1.2, 
      '• sin(π-α) = sin α (симметрия относительно OY)\n' +
      '• sin(π+α) = -sin α (центральная симметрия)\n' +
      '• sin(-α) = -sin α (симметрия относительно OX)'
    ], {
      fontSize: 10,
      color: '#6c757d',
      fixed: true
    });

    return () => board.unsuspendUpdate();
  }, []);

  return (
    <div>
      <div ref={boardRef} style={{ height: "400px", width: "400px" }} />
      <div className="text-center mt-2">
        <small className="text-muted">Измените угол α, чтобы увидеть симметричные углы</small>
      </div>
    </div>
  );
};

export default ReductionFormulas;