import React, { useEffect } from "react";

import { Card, InputGroup, FormControl, Button } from "react-bootstrap"

import MixedContent from "./MixedContent";

import useMathQuiz from "../../hooks/useMathQuiz";


function MathQuiz(quiz) {
    const { processedText, processedHint, calculatedAnswer, handleAnswerChange, isCorrect: answerIsRight,
        isAnswered, handleCheckAnswer, userAnswer } = useMathQuiz(quiz)

    return <Card bg={"light"} style={{ width: "95%", margin: "1rem" }}>
        <Card.Header >{quiz.header}</Card.Header>
        <Card.Body>
            <Card.Title>{!!quiz?.setId ? quiz.setId : ""} {quiz.title}</Card.Title>

              <MixedContent
          content={processedText}
          className="m-3 math-text"
        ></MixedContent>

        </Card.Body>

        {isAnswered && !quiz?.isExam ? <InputGroup size="sm" style={{ width: "95%", margin: "1rem" }}>
            <InputGroup.Text id="basic-addon1">
                <span
                    className={answerIsRight ? "text-success" : "text-danger"}
                >
                    Правильный ответ: {calculatedAnswer}, ваш ответ: {userAnswer}
                </span>
            </InputGroup.Text>
        </InputGroup> :
            <InputGroup size="sm" style={{ width: "95%", margin: "1rem" }}>

                <Button variant="outline-secondary" size="sm" onClick={handleCheckAnswer}>
                    Ответ
                </Button>

                <FormControl
                    value={userAnswer}
                    type="number"
                    onChange={(e) => handleAnswerChange(e.target.value)}
                    aria-label="Answer"
                    aria-describedby="inputGroup-answer"
                />
            </InputGroup>
        }

        {!!quiz?.hint && isAnswered && !quiz?.isExam ? 

         <MixedContent
          content={processedHint}
          className="m-3 math-text"
        ></MixedContent>

       

        // <div className="m-3" dangerouslySetInnerHTML={{ __html: 

        //      <MathText
        //         text={processedHint}
        //         className="card-text m-3 math-text"
        //     />
        //  }} />
         : null}
    </Card>



}

export default MathQuiz