import * as THREE from 'three';

export function createClassicStereometryScene(container, options = {}) {
    const {
        figureType = 'cube',
        size = 1,
        showVertices = true,
        showEdges = true,
        showFaces = false,
        vertexSize = 0.03,
        edgeWidth = 2,
        faceColor = 0xf8f9fa,
        edgeColor = 0x212529,
        vertexColor = 0xdc3545,
        rotationSpeed = 0.005,
        smoothCurves = true,
        is2D = false,
        // Новые опции для координатной плоскости
        showGrid = false,
        showAxes = false,
        coordinates = null,
        vertexLabels = null,
        radius = null,
        showLine = false
    } = options;

    // Сцена с белым фоном
    const scene = new THREE.Scene();
    scene.background = new THREE.Color(0xffffff);
    
    const camera = new THREE.PerspectiveCamera(60, container.clientWidth / container.clientHeight, 0.1, 1000);
    
    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(container.clientWidth, container.clientHeight);
    renderer.setClearColor(0xffffff);
    container.innerHTML = '';
    container.appendChild(renderer.domElement);

    // Основная группа для всей сцены
    const sceneGroup = new THREE.Group();
    scene.add(sceneGroup);

    // Группа для фигуры
    const figureGroup = new THREE.Group();
    sceneGroup.add(figureGroup);

    // Для 2D фигур отключаем вращение и настраиваем камеру
    if (is2D) {
        rotationSpeed = 0;
        camera.position.set(0, 0, size * 3);
        camera.lookAt(0, 0, 0);
    }

    let geometry;
    let figureMesh;

    // ========== ФУНКЦИИ ДЛЯ ГЛАДКИХ КРИВЫХ ==========

    function createSmoothCircle(radius, segments = 32) {
        const points = [];
        for (let i = 0; i <= segments; i++) {
            const angle = (i / segments) * Math.PI * 2;
            points.push(new THREE.Vector3(
                Math.cos(angle) * radius,
                0,
                Math.sin(angle) * radius
            ));
        }
        const geometry = new THREE.BufferGeometry().setFromPoints(points);
        return geometry;
    }

    function createSmoothCylinder(radius, height, segments = 32) {
        const group = new THREE.Group();
        
        // Верхняя окружность
        const topCircle = new THREE.Line(
            createSmoothCircle(radius, segments),
            new THREE.LineBasicMaterial({ color: edgeColor })
        );
        topCircle.position.y = height / 2;
        group.add(topCircle);
        
        // Нижняя окружность
        const bottomCircle = new THREE.Line(
            createSmoothCircle(radius, segments),
            new THREE.LineBasicMaterial({ color: edgeColor })
        );
        bottomCircle.position.y = -height / 2;
        group.add(bottomCircle);
        
        // Вертикальные линии
        const verticalLines = new THREE.Group();
        for (let i = 0; i < segments; i += 4) {
            const angle = (i / segments) * Math.PI * 2;
            const points = [
                new THREE.Vector3(Math.cos(angle) * radius, -height / 2, Math.sin(angle) * radius),
                new THREE.Vector3(Math.cos(angle) * radius, height / 2, Math.sin(angle) * radius)
            ];
            const lineGeometry = new THREE.BufferGeometry().setFromPoints(points);
            const line = new THREE.Line(
                lineGeometry,
                new THREE.LineBasicMaterial({ color: edgeColor })
            );
            verticalLines.add(line);
        }
        group.add(verticalLines);
        
        return group;
    }

    function createSmoothCone(radius, height, segments = 32) {
        const group = new THREE.Group();
        
        // Основание
        const baseCircle = new THREE.Line(
            createSmoothCircle(radius, segments),
            new THREE.LineBasicMaterial({ color: edgeColor })
        );
        baseCircle.position.y = -height / 2;
        group.add(baseCircle);
        
        // Линии к вершине
        const sideLines = new THREE.Group();
        for (let i = 0; i < segments; i += 4) {
            const angle = (i / segments) * Math.PI * 2;
            const points = [
                new THREE.Vector3(Math.cos(angle) * radius, -height / 2, Math.sin(angle) * radius),
                new THREE.Vector3(0, height / 2, 0)
            ];
            const lineGeometry = new THREE.BufferGeometry().setFromPoints(points);
            const line = new THREE.Line(
                lineGeometry,
                new THREE.LineBasicMaterial({ color: edgeColor })
            );
            sideLines.add(line);
        }
        group.add(sideLines);
        
        return group;
    }

    function createSmoothSphere(radius, segments = 16) {
        const group = new THREE.Group();
        
        // Меридианы
        for (let i = 0; i < segments; i++) {
            const points = [];
            for (let j = 0; j <= segments; j++) {
                const phi = (j / segments) * Math.PI;
                const theta = (i / segments) * Math.PI * 2;
                points.push(new THREE.Vector3(
                    Math.sin(phi) * Math.cos(theta) * radius,
                    Math.cos(phi) * radius,
                    Math.sin(phi) * Math.sin(theta) * radius
                ));
            }
            const meridian = new THREE.Line(
                new THREE.BufferGeometry().setFromPoints(points),
                new THREE.LineBasicMaterial({ color: edgeColor })
            );
            group.add(meridian);
        }
        
        // Параллели
        for (let i = 1; i < segments; i++) {
            const points = [];
            const phi = (i / segments) * Math.PI;
            const y = Math.cos(phi) * radius;
            const parallelRadius = Math.sin(phi) * radius;
            
            for (let j = 0; j <= segments; j++) {
                const theta = (j / segments) * Math.PI * 2;
                points.push(new THREE.Vector3(
                    Math.cos(theta) * parallelRadius,
                    y,
                    Math.sin(theta) * parallelRadius
                ));
            }
            const parallel = new THREE.Line(
                new THREE.BufferGeometry().setFromPoints(points),
                new THREE.LineBasicMaterial({ color: edgeColor })
            );
            group.add(parallel);
        }
        
        return group;
    }

    // ========== ФУНКЦИИ ДЛЯ 2D ФИГУР ==========

    function create2DCircle(radius, segments = 32) {
        const circle = new THREE.Line(
            createSmoothCircle(radius, segments),
            new THREE.LineBasicMaterial({ color: edgeColor })
        );
        return circle;
    }

    function create2DSquare(size) {
        const points = [
            new THREE.Vector3(-size/2, 0, -size/2),
            new THREE.Vector3(size/2, 0, -size/2),
            new THREE.Vector3(size/2, 0, size/2),
            new THREE.Vector3(-size/2, 0, size/2),
            new THREE.Vector3(-size/2, 0, -size/2)
        ];
        const geometry = new THREE.BufferGeometry().setFromPoints(points);
        const square = new THREE.Line(
            geometry,
            new THREE.LineBasicMaterial({ color: edgeColor })
        );
        return square;
    }

    function create2DTriangle(size) {
        const height = (Math.sqrt(3) / 2) * size;
        const points = [
            new THREE.Vector3(0, 0, height/2),
            new THREE.Vector3(-size/2, 0, -height/2),
            new THREE.Vector3(size/2, 0, -height/2),
            new THREE.Vector3(0, 0, height/2)
        ];
        const geometry = new THREE.BufferGeometry().setFromPoints(points);
        const triangle = new THREE.Line(
            geometry,
            new THREE.LineBasicMaterial({ color: edgeColor })
        );
        return triangle;
    }

    function create2DRectangle(width, height) {
        const points = [
            new THREE.Vector3(-width/2, 0, -height/2),
            new THREE.Vector3(width/2, 0, -height/2),
            new THREE.Vector3(width/2, 0, height/2),
            new THREE.Vector3(-width/2, 0, height/2),
            new THREE.Vector3(-width/2, 0, -height/2)
        ];
        const geometry = new THREE.BufferGeometry().setFromPoints(points);
        const rectangle = new THREE.Line(
            geometry,
            new THREE.LineBasicMaterial({ color: edgeColor })
        );
        return rectangle;
    }

    function create2DHexagon(size) {
        const points = [];
        for (let i = 0; i <= 6; i++) {
            const angle = (i / 6) * Math.PI * 2;
            points.push(new THREE.Vector3(
                Math.cos(angle) * size,
                0,
                Math.sin(angle) * size
            ));
        }
        const geometry = new THREE.BufferGeometry().setFromPoints(points);
        const hexagon = new THREE.Line(
            geometry,
            new THREE.LineBasicMaterial({ color: edgeColor })
        );
        return hexagon;
    }

    function create2DPentagon(size) {
        const points = [];
        for (let i = 0; i <= 5; i++) {
            const angle = (i / 5) * Math.PI * 2 - Math.PI / 2;
            points.push(new THREE.Vector3(
                Math.cos(angle) * size,
                0,
                Math.sin(angle) * size
            ));
        }
        const geometry = new THREE.BufferGeometry().setFromPoints(points);
        const pentagon = new THREE.Line(
            geometry,
            new THREE.LineBasicMaterial({ color: edgeColor })
        );
        return pentagon;
    }

    function create2DTrapezoid(width1, width2, height) {
        const points = [
            new THREE.Vector3(-width1/2, 0, -height/2),
            new THREE.Vector3(width1/2, 0, -height/2),
            new THREE.Vector3(width2/2, 0, height/2),
            new THREE.Vector3(-width2/2, 0, height/2),
            new THREE.Vector3(-width1/2, 0, -height/2)
        ];
        const geometry = new THREE.BufferGeometry().setFromPoints(points);
        const trapezoid = new THREE.Line(
            geometry,
            new THREE.LineBasicMaterial({ color: edgeColor })
        );
        return trapezoid;
    }

    function create2DLine(point1, point2) {
        const points = [
            new THREE.Vector3(point1[0], 0, point1[1]),
            new THREE.Vector3(point2[0], 0, point2[1])
        ];
        const geometry = new THREE.BufferGeometry().setFromPoints(points);
        const line = new THREE.Line(
            geometry,
            new THREE.LineBasicMaterial({ color: edgeColor, linewidth: 2 })
        );
        return line;
    }

    // ========== КООРДИНАТНАЯ СИСТЕМА ==========

    function createCoordinateSystem() {
        const group = new THREE.Group();
        
        // Сетка
        if (showGrid) {
            const gridSize = size * 3;
            const gridDivisions = 10;
            const gridHelper = new THREE.GridHelper(gridSize, gridDivisions, 0xcccccc, 0xcccccc);
            gridHelper.position.y = -0.01; // Чуть ниже фигуры
            group.add(gridHelper);
        }
        
        // Оси координат
        if (showAxes) {
            const axesSize = size * 2;
            const axesHelper = new THREE.AxesHelper(axesSize);
            group.add(axesHelper);
        }
        
        return group;
    }

    // ========== СОЗДАНИЕ ФИГУРЫ ==========

    // Добавляем координатную систему если нужно
    if (showGrid || showAxes) {
        const coordSystem = createCoordinateSystem();
        sceneGroup.add(coordSystem);
    }

    // Создание фигуры по координатам если заданы
    if (coordinates && coordinates.length > 0) {
        figureMesh = createFigureFromCoordinates();
    } else {
        // Создание стандартной фигуры
        figureMesh = createStandardFigure();
    }

    if (figureMesh) {
        figureGroup.add(figureMesh);
    }

    function createFigureFromCoordinates() {
        const group = new THREE.Group();
        
        // Создаем вершины
        if (showVertices) {
            const verticesArray = coordinates.flat();
            const verticesGeometry = new THREE.BufferGeometry();
            verticesGeometry.setAttribute('position', new THREE.Float32BufferAttribute(verticesArray, 3));
            
            const verticesMaterial = new THREE.PointsMaterial({
                color: vertexColor,
                size: vertexSize,
                sizeAttenuation: false
            });
            
            const vertices = new THREE.Points(verticesGeometry, verticesMaterial);
            group.add(vertices);
        }
        
        // Создаем рёбра/контур
        if (showEdges) {
            const points = coordinates.map(coord => 
                new THREE.Vector3(coord[0], 0, coord[1])
            );
            // Замыкаем контур если нужно
            if (figureType !== 'line' && coordinates.length > 2) {
                points.push(points[0]);
            }
            
            const geometry = new THREE.BufferGeometry().setFromPoints(points);
            const line = new THREE.Line(
                geometry,
                new THREE.LineBasicMaterial({ color: edgeColor, linewidth: edgeWidth })
            );
            group.add(line);
        }
        
        // Создаем линию между двумя точками
        if (showLine && coordinates.length === 2) {
            const line = create2DLine(coordinates[0], coordinates[1]);
            group.add(line);
        }
        
        return group;
    }

    function createStandardFigure() {
        let mesh;
        
        switch(figureType) {
            case 'cube':
                if (is2D) {
                    mesh = create2DSquare(size);
                } else {
                    geometry = new THREE.BoxGeometry(size, size, size);
                    if (showEdges) {
                        const edgesGeometry = new THREE.EdgesGeometry(geometry);
                        mesh = new THREE.LineSegments(
                            edgesGeometry,
                            new THREE.LineBasicMaterial({ color: edgeColor, linewidth: edgeWidth })
                        );
                    }
                }
                break;
                
            case 'sphere':
                if (is2D) {
                    mesh = create2DCircle(radius || size);
                } else if (smoothCurves) {
                    mesh = createSmoothSphere(radius || size, 16);
                } else {
                    geometry = new THREE.SphereGeometry(radius || size, 12, 8);
                    if (showEdges) {
                        const edgesGeometry = new THREE.EdgesGeometry(geometry);
                        mesh = new THREE.LineSegments(
                            edgesGeometry,
                            new THREE.LineBasicMaterial({ color: edgeColor })
                        );
                    }
                }
                break;
                
            case 'cylinder':
                if (is2D) {
                    mesh = create2DRectangle(size, size * 1.5);
                } else if (smoothCurves) {
                    mesh = createSmoothCylinder(size/2, size * 1.5, 32);
                } else {
                    geometry = new THREE.CylinderGeometry(size/2, size/2, size * 1.5, 12);
                    if (showEdges) {
                        const edgesGeometry = new THREE.EdgesGeometry(geometry);
                        mesh = new THREE.LineSegments(
                            edgesGeometry,
                            new THREE.LineBasicMaterial({ color: edgeColor })
                        );
                    }
                }
                break;
                
            case 'cone':
                if (is2D) {
                    mesh = create2DTriangle(size * 1.2);
                } else if (smoothCurves) {
                    mesh = createSmoothCone(size, size * 2, 32);
                } else {
                    geometry = new THREE.ConeGeometry(size, size * 2, 12);
                    if (showEdges) {
                        const edgesGeometry = new THREE.EdgesGeometry(geometry);
                        mesh = new THREE.LineSegments(
                            edgesGeometry,
                            new THREE.LineBasicMaterial({ color: edgeColor })
                        );
                    }
                }
                break;
                
            case 'pyramid':
                if (is2D) {
                    mesh = create2DTriangle(size * 1.2);
                } else {
                    geometry = new THREE.ConeGeometry(size, size * 1.5, 4);
                    if (showEdges) {
                        const edgesGeometry = new THREE.EdgesGeometry(geometry);
                        mesh = new THREE.LineSegments(
                            edgesGeometry,
                            new THREE.LineBasicMaterial({ color: edgeColor })
                        );
                    }
                }
                break;
                
            case 'prism':
                if (is2D) {
                    mesh = create2DHexagon(size);
                } else {
                    geometry = new THREE.CylinderGeometry(size/2, size/2, size * 1.5, 6);
                    if (showEdges) {
                        const edgesGeometry = new THREE.EdgesGeometry(geometry);
                        mesh = new THREE.LineSegments(
                            edgesGeometry,
                            new THREE.LineBasicMaterial({ color: edgeColor })
                        );
                    }
                }
                break;
                
            case 'square':
                mesh = create2DSquare(size);
                break;
                
            case 'circle':
                mesh = create2DCircle(radius || size);
                break;
                
            case 'triangle':
                mesh = create2DTriangle(size);
                break;
                
            case 'rectangle':
                mesh = create2DRectangle(size, size * 0.6);
                break;
                
            case 'hexagon':
                mesh = create2DHexagon(size);
                break;
                
            case 'pentagon':
                mesh = create2DPentagon(size);
                break;
                
            case 'trapezoid':
                mesh = create2DTrapezoid(size, size * 0.7, size);
                break;
                
            case 'line':
                if (coordinates && coordinates.length === 2) {
                    mesh = create2DLine(coordinates[0], coordinates[1]);
                }
                break;
                
            default:
                if (is2D) {
                    mesh = create2DSquare(size);
                } else {
                    geometry = new THREE.BoxGeometry(size, size, size);
                    if (showEdges) {
                        const edgesGeometry = new THREE.EdgesGeometry(geometry);
                        mesh = new THREE.LineSegments(
                            edgesGeometry,
                            new THREE.LineBasicMaterial({ color: edgeColor })
                        );
                    }
                }
        }
        
        return mesh;
    }

    // Полупрозрачные грани для многогранников
    if (showFaces && geometry && !smoothCurves && !is2D) {
        const faceMaterial = new THREE.MeshBasicMaterial({
            color: faceColor,
            transparent: true,
            opacity: 0.1,
            side: THREE.DoubleSide
        });
        const faces = new THREE.Mesh(geometry, faceMaterial);
        figureGroup.add(faces);
    }

    // Освещение (для 2D минимальное)
    const ambientLight = new THREE.AmbientLight(0x404040, is2D ? 0.8 : 0.6);
    scene.add(ambientLight);

    if (!is2D) {
        const directionalLight = new THREE.DirectionalLight(0xffffff, 0.8);
        directionalLight.position.set(2, 3, 4);
        scene.add(directionalLight);
    }

    // Позиция камеры
    camera.position.set(0, 0, size * (is2D ? 3 : 4));
    camera.lookAt(0, 0, 0);

    // Анимация
    let animationId;
    const animate = () => {
        animationId = requestAnimationFrame(animate);
        
        if (!is2D) {
            figureGroup.rotation.x += rotationSpeed;
            figureGroup.rotation.y += rotationSpeed * 0.7;
        }
        
        renderer.render(scene, camera);
    };

    const handleResize = () => {
        const width = container.clientWidth;
        const height = container.clientHeight;
        
        camera.aspect = width / height;
        camera.updateProjectionMatrix();
        renderer.setSize(width, height);
    };

    window.addEventListener('resize', handleResize);
    animate();
    handleResize();

    // Функция очистки
    const cleanup = () => {
        if (animationId) {
            cancelAnimationFrame(animationId);
        }
        window.removeEventListener('resize', handleResize);
        
        if (container.contains(renderer.domElement)) {
            container.removeChild(renderer.domElement);
        }
        
        renderer.dispose();
        if (geometry) geometry.dispose();
    };

    return cleanup;
}