import React, { useEffect, useRef } from 'react';
import katex from 'katex';

const TriangleSolver = () => {
  const boardRef = useRef(null);

  useEffect(() => {
    const board = window.JXG.JSXGraph.initBoard(boardRef.current, {
      boundingbox: [-1, 5, 7, -1],
      axis: false,
      grid: false,
      showNavigation: false,
      showCopyright: false
    });

    const colors = {
      triangle: '#212529',
      sideA: '#dc3545',
      sideB: '#007bff',
      sideC: '#28a745',
      angle: '#ffc107'
    };

    // Вершины треугольника (можно менять точку B)
    const A = board.create('point', [0, 0], {
      name: 'A', size: 4, color: colors.triangle, fixed: true
    });

    const B = board.create('point', [5, 0], {
      name: 'B', size: 4, color: colors.triangle, fixed: false
    });

    const C = board.create('point', [2, 3], {
      name: 'C', size: 4, color: colors.triangle, fixed: false
    });

    // Стороны треугольника
    const sideAB = board.create('segment', [A, B], {
      strokeColor: colors.sideA,
      strokeWidth: 3,
      label: { text: 'c', color: colors.sideA, fontSize: 14 }
    });

    const sideBC = board.create('segment', [B, C], {
      strokeColor: colors.sideB,
      strokeWidth: 3,
      label: { text: 'a', color: colors.sideB, fontSize: 14 }
    });

    const sideCA = board.create('segment', [C, A], {
      strokeColor: colors.sideC,
      strokeWidth: 3,
      label: { text: 'b', color: colors.sideC, fontSize: 14 }
    });

    // Углы
    const angleA = board.create('angle', [B, A, C], {
      radius: 0.8,
      color: colors.angle,
      fillColor: colors.angle + '40',
      label: { text: 'α', color: colors.angle, fontSize: 14 }
    });

    const angleB = board.create('angle', [C, B, A], {
      radius: 0.7,
      color: colors.angle,
      fillColor: colors.angle + '40',
      label: { text: 'β', color: colors.angle, fontSize: 14 }
    });

    const angleC = board.create('angle', [A, C, B], {
      radius: 0.6,
      color: colors.angle,
      fillColor: colors.angle + '40',
      label: { text: 'γ', color: colors.angle, fontSize: 14 }
    });

    // Вычисления
    const calculateTriangle = () => {
      const ax = A.X(), ay = A.Y();
      const bx = B.X(), by = B.Y();
      const cx = C.X(), cy = C.Y();
      
      // Длины сторон
      const a = Math.sqrt((bx - cx)**2 + (by - cy)**2);
      const b = Math.sqrt((cx - ax)**2 + (cy - ay)**2);
      const c = Math.sqrt((bx - ax)**2 + (by - ay)**2);
      
      // Углы по теореме косинусов
      const alpha = Math.acos((b**2 + c**2 - a**2) / (2 * b * c));
      const beta = Math.acos((a**2 + c**2 - b**2) / (2 * a * c));
      const gamma = Math.PI - alpha - beta;
      
      return { a, b, c, alpha, beta, gamma };
    };

    // Дисплей с данными
    const dataBox = board.create('text', [0.5, 4.5, ''], {
      fontSize: 12,
      color: '#212529',
      fixed: true,
      parse: false
    });

    const formulaBox = board.create('text', [3.5, 4.5, ''], {
      fontSize: 12,
      color: '#212529',
      fixed: true,
      parse: false
    });

    const updateDisplay = () => {
      const { a, b, c, alpha, beta, gamma } = calculateTriangle();
      
      // Данные
      const dataText = `a = ${a.toFixed(2)}, b = ${b.toFixed(2)}, c = ${c.toFixed(2)}\\\\α = ${(alpha*180/Math.PI).toFixed(1)}°, β = ${(beta*180/Math.PI).toFixed(1)}°, γ = ${(gamma*180/Math.PI).toFixed(1)}°`;
      
      // Теорема косинусов для стороны a
      const theoremText = `a² = b² + c² - 2bc·cosα\\\\= ${b.toFixed(2)}² + ${c.toFixed(2)}² - 2·${b.toFixed(2)}·${c.toFixed(2)}·cos(${(alpha*180/Math.PI).toFixed(1)}°)\\\\= ${a.toFixed(2)}²`;
      
      try {
        const dataHtml = katex.renderToString(dataText, {
          displayMode: false,
          throwOnError: false
        });
        dataBox.setText(dataHtml);
        
        const theoremHtml = katex.renderToString(theoremText, {
          displayMode: false,
          throwOnError: false
        });
        formulaBox.setText(theoremHtml);
      } catch (error) {
        dataBox.setText(dataText);
        formulaBox.setText(theoremText);
      }
    };

    [A, B, C].forEach(point => {
      point.on('drag', updateDisplay);
      point.on('up', updateDisplay);
    });

    updateDisplay();

    // Теорема синусов
    const sineTheoremBox = board.create('text', [0.5, 3.5, ''], {
      fontSize: 12,
      color: '#6f42c1',
      fixed: true,
      parse: false
    });

    const updateSineTheorem = () => {
      const { a, b, c, alpha, beta, gamma } = calculateTriangle();
      
      const theoremText = `\\frac{a}{\\sin\\alpha} = \\frac{b}{\\sin\\beta} = \\frac{c}{\\sin\\gamma}\\\\${(a/Math.sin(alpha)).toFixed(2)} ≈ ${(b/Math.sin(beta)).toFixed(2)} ≈ ${(c/Math.sin(gamma)).toFixed(2)}`;
      
      try {
        const html = katex.renderToString(theoremText, {
          displayMode: false,
          throwOnError: false
        });
        sineTheoremBox.setText(html);
      } catch (error) {
        sineTheoremBox.setText(theoremText);
      }
    };

    [A, B, C].forEach(point => {
      point.on('drag', updateSineTheorem);
      point.on('up', updateSineTheorem);
    });

    updateSineTheorem();

    return () => board.unsuspendUpdate();
  }, []);

  return (
    <div>
      <div ref={boardRef} style={{ height: "400px", width: "400px" }} />
      <div className="text-center mt-2">
        <small className="text-muted">Перемещайте вершины треугольника</small>
      </div>
    </div>
  );
};

export default TriangleSolver;