import React, { useEffect, useRef } from 'react';
//import JXG from 'jsxgraph';

const CircleWithChords = () => {
  const boardRef = useRef(null);

  useEffect(() => {
    const board = JXG.JSXGraph.initBoard(boardRef.current, {
      boundingbox: [-6, 6, 6, -6],
      axis: false,
      grid: false,
      showNavigation: false,
      showCopyright: false
    });

    // Создаем окружность с центром в O(0,0) и радиусом 4
    const O = board.create('point', [0, 0], { name: 'O', size: 4, color: 'black' });
    const circle = board.create('circle', [O, 4], { 
      strokeColor: 'blue', 
      strokeWidth: 2,
      fillColor: '#f0f8ff',
      fillOpacity: 0.3
    });

    // Создаем точки на окружности
    const A = board.create('point', [4, 0], { name: 'A', size: 4, color: 'red' });
    const B = board.create('point', [0, 4], { name: 'B', size: 4, color: 'red' });
    const C = board.create('point', [-4, 0], { name: 'C', size: 4, color: 'red' });
    const D = board.create('point', [2.828, 2.828], { name: 'D', size: 4, color: 'red' }); // 45°

    // Хорды
    board.create('segment', [A, B], { strokeColor: 'green', strokeWidth: 2 }); // Хорда AB
    board.create('segment', [B, C], { strokeColor: 'green', strokeWidth: 2 }); // Хорда BC
    board.create('segment', [A, D], { strokeColor: 'orange', strokeWidth: 2 }); // Хорда AD
    board.create('segment', [D, B], { strokeColor: 'orange', strokeWidth: 2 }); // Хорда DB

    // Центральный угол AOB
    const centralAngle = board.create('angle', [A, O, B], {
      radius: 2,
      color: 'purple',
      fillOpacity: 0.3,
      name: '90°'
    });

    // Вписанный угол ADB
    const inscribedAngle = board.create('angle', [A, D, B], {
      radius: 1,
      color: 'red',
      fillOpacity: 0.3,
      name: '45°'
    });

    // Радиусы
    board.create('segment', [O, A], { strokeColor: 'gray', strokeWidth: 1, dash: 1 });
    board.create('segment', [O, B], { strokeColor: 'gray', strokeWidth: 1, dash: 1 });
    board.create('segment', [O, D], { strokeColor: 'gray', strokeWidth: 1, dash: 1 });

    // Подписи
    board.create('text', [2, 2.2, 'R = 4'], { fontSize: 12, color: 'darkblue' });
    board.create('text', [1, 0.5, '90°'], { fontSize: 12, color: 'purple' });
    board.create('text', [3, 2, '45°'], { fontSize: 12, color: 'red' });
    board.create('text', [2, -0.3, 'Хорда AB'], { fontSize: 11, color: 'darkgreen' });

    // Теорема о вписанном угле
    board.create('text', [-5, 5, '∠AOB = 2 × ∠ADB'], { fontSize: 12, color: 'darkred' });

    return () => board.unsuspendUpdate();
  }, []);

  return (
    <div>
      <h3>Окружность с хордами и углами</h3>
      <div>Радиус R = 4, центральный угол ∠AOB = 90°, вписанный угол ∠ADB = 45°</div>
      <div ref={boardRef} style={{ width: '100%', height: '500px' }} />
    </div>
  );
};

export default CircleWithChords;