import { useContext } from "react";
import { QuizContext } from "./QuizContext";
import ProcessKatex from "./ProcessKatex";

function QuizFeedback() {
    const { isAnswered, isCorrect, isExam, hint, 
        answers, type, selectedAnswers, text = "", id, title, theme, userAnswer, userAnswers
    } = useContext(QuizContext)

    if (!isExam && isAnswered && isCorrect) {
        return <div className="my-2">
             <div className="text-success">Правильно</div>
            <ProcessKatex
                text={hint}
                className="card-text m-1 math-text"
            />
        </div>
    }

    if (!isExam && isAnswered && !isCorrect) {
        return <div className="my-2">
             <div className="text-danger">Не правильно</div>
            <ProcessKatex
                text={hint}
                className="card-text m-1 math-text"
            />
        </div>
    }

    return null
}

export default QuizFeedback