import React, { useEffect, useRef } from 'react';
//import JXG from 'jsxgraph';

const Cylinder3D = () => {
  const boardRef = useRef(null);

  useEffect(() => {
    const board = JXG.JSXGraph.initBoard(boardRef.current, {
      boundingbox: [-3, 5, 5, -1],
      axis: true,
      grid: true,
      showNavigation: false,
      showCopyright: false
    });

    // Центры оснований
    const O1 = board.create('point', [0, 0], { name: 'O₁', size: 4, color: 'blue' });
    const O2 = board.create('point', [0, 3], { name: 'O₂', size: 4, color: 'red' });
    
    // Окружности оснований
    const circle1 = board.create('circle', [O1, 2], {
      strokeColor: 'blue',
      strokeWidth: 2,
      fillColor: 'lightblue',
      fillOpacity: 0.2
    });

    const circle2 = board.create('circle', [O2, 2], {
      strokeColor: 'red',
      strokeWidth: 2,
      fillColor: 'lightcoral',
      fillOpacity: 0.2
    });

    // Образующие
    const A = board.create('point', [2, 0], { name: 'A', size: 3, color: 'blue' });
    const A1 = board.create('point', [2, 3], { name: "A'", size: 3, color: 'red' });
    
    board.create('segment', [A, A1], {
      strokeColor: 'green',
      strokeWidth: 2
    });

    // Диаметр
    const B = board.create('point', [-2, 0], { name: 'B', size: 3, color: 'blue' });
    board.create('segment', [A, B], {
      strokeColor: 'blue',
      strokeWidth: 2,
      dash: 1
    });

    // Ось цилиндра
    board.create('segment', [O1, O2], {
      strokeColor: 'purple',
      strokeWidth: 2,
      dash: 2
    });

    // Подписи
    board.create('text', [2.3, 1.5, 'h = 3'], { fontSize: 12, color: 'darkgreen' });
    board.create('text', [0, -0.3, 'R = 2'], { fontSize: 12, color: 'darkblue' });
    board.create('text', [0, 3.3, 'R = 2'], { fontSize: 12, color: 'darkred' });

    // Формулы
    board.create('text', [-2.8, 4.5, 'V = πR²h = π·4·3 = 12π'], {
      fontSize: 14,
      color: 'darkgreen',
      anchorX: 'left'
    });

    return () => board.unsuspendUpdate();
  }, []);

  return (
    <div>
      <h4>Цилиндр: R = 2, h = 3</h4>
      <div ref={boardRef} style={{ width: '100%', height: '500px' }} />
    </div>
  );
};

export default Cylinder3D;