import React, { useEffect, useRef } from 'react';
//import { createSimpleCubeScene } from './simpleCubeScene';
//import { createCubeScene } from './cubeScene';
//import { createStereometryScene, stereometryConfigs } from './createStereometryScene';
//import { createCenteredStereometryScene } from './centeredStereometryScene';

import { createClassicStereometryScene } from "./createClassicStereometryScene";

const ThreeJSViewer = ({ 
    figureType = 'cube',
    size = 1,
    showVertices = true,
    showEdges = true,
    showFaces = true,
    className = '',
    style = {} 
}) => {
    const mountRef = useRef(null);

    useEffect(() => {
        const container = mountRef.current;
        if (!container) return;
        
    //        const cleanupFunction = createStereometryScene(mountRef.current, {
    //         figureType,
    //         size,
    //         color,
    //         showVertices,
    //         rotationSpeed,
    //         showLabels
    //     });

    //     // Очистка при размонтировании компонента
    //     return cleanupFunction;
    //     // const cleanup = createCubeScene(container, {
    //     //     size,
    //     //     color,
    //     //     rotationSpeed,
    //     //     showVertices
    //     // });
        
    //     // return cleanup;
    // }, [figureType, size, color, rotationSpeed, showVertices]);
    const cleanup = createClassicStereometryScene(mountRef.current, {
            figureType,
            size,
            showVertices,
            showEdges,
            showFaces
        });

        return cleanup;
    }, [figureType, size, showVertices, showEdges, showFaces]);

    return (
        <div 
            ref={mountRef} 
            className={className}
            style={{ 
                width: '100%',
                height: '400px',
                border: '1px solid #dee2e6',
                borderRadius: '4px',
                ...style
            }} 
        />
    );
};

export default ThreeJSViewer