import React, { useState, useEffect } from 'react';

import useDebounce from '../../utilities/useDebounce';
import { Container, Form } from 'react-bootstrap';

function QuickCalculator() {
    const [query, setQuery] = useState('');
    const [result, setResult] = useState('');
    const [isLoading, setIsLoading] = useState(false);

    const debouncedQuery = useDebounce(query, 1000);

    const parser = new formulaParser.Parser();

    useEffect(() => {
        if (debouncedQuery) {
            setIsLoading(true);

            try {
                let parseResult = parser.parse(query);
                console.log(parseResult);
                if (parseResult.error === null) {
                    setResult(parseResult.result);
                    setIsLoading(false);
                } else {
                    setResult(":-(");
                    setIsLoading(false);
                }

            } catch (error) {
                setResult(":-(");
                setIsLoading(false);
            }

        } else {
            setResult('');
            setIsLoading(false);
        }
    }, [debouncedQuery]); // The API call effect runs only when debouncedQuery changes

    const handleInputChange = (e) => {
        setQuery(e.target.value);
    };

    console.log(query, result, isLoading)


    return <Container>
        <hr className='m-3' />
        <Form.Group>
            <Form.Label size="sm" className="text-secondary">Калькулятор</Form.Label>
            <Form.Control
                size='sm'
                type="text"
                placeholder="2+2"
                value={query}
                onChange={handleInputChange}
            />
        </Form.Group>

       

        <div className="mb-3">
            {isLoading ? <div className="text-secondary">...</div> : <div className="text-secondary">{result}</div>}
        </div>

         <hr className='m-3' />

    </Container>
}

export default QuickCalculator