import React, { useEffect, useRef } from 'react';
//import JXG from 'jsxgraph';

const Cube3D = () => {
  const boardRef = useRef(null);

  useEffect(() => {
    const board = JXG.JSXGraph.initBoard(boardRef.current, {
      boundingbox: [-2, 4, 4, -2],
      axis: true,
      grid: true,
      showNavigation: false,
      showCopyright: false
    });

    // Вершины куба со стороной 2
    const A = board.create('point', [0, 0], { name: 'A', size: 4, color: 'blue' });
    const B = board.create('point', [2, 0], { name: 'B', size: 4, color: 'blue' });
    const D = board.create('point', [0, 2], { name: 'D', size: 4, color: 'blue' });
    const C = board.create('point', [2, 2], { name: 'C', size: 4, color: 'blue' });
    
    // Верхние вершины (смещенные для 3D эффекта)
    const A1 = board.create('point', [0.7, 2.7], { name: "A'", size: 4, color: 'red' });
    const B1 = board.create('point', [2.7, 2.7], { name: "B'", size: 4, color: 'red' });
    const D1 = board.create('point', [0.7, 4.7], { name: "D'", size: 4, color: 'red' });
    const C1 = board.create('point', [2.7, 4.7], { name: "C'", size: 4, color: 'red' });

    // Нижнее основание
    board.create('polygon', [A, B, C, D], {
      fillColor: 'lightblue',
      fillOpacity: 0.3,
      borders: { strokeColor: 'blue', strokeWidth: 2 }
    });

    // Верхнее основание
    board.create('polygon', [A1, B1, C1, D1], {
      fillColor: 'lightcoral',
      fillOpacity: 0.3,
      borders: { strokeColor: 'red', strokeWidth: 2 }
    });

    // Боковые ребра
    const edges = [[A, A1], [B, B1], [C, C1], [D, D1]];
    edges.forEach(edge => {
      board.create('segment', edge, {
        strokeColor: 'green',
        strokeWidth: 2,
        dash: 1
      });
    });

    // Диагонали
    board.create('segment', [A, C1], {
      strokeColor: 'purple',
      strokeWidth: 2,
      dash: 2
    });

    board.create('segment', [A1, C], {
      strokeColor: 'purple',
      strokeWidth: 2,
      dash: 2
    });

    // Подписи размеров
    board.create('text', [1, -0.3, 'a = 2'], { fontSize: 12, color: 'darkblue' });
    board.create('text', [2.3, 1, 'a = 2'], { fontSize: 12, color: 'darkblue' });
    board.create('text', [1.7, 3.7, 'h = 2'], { fontSize: 12, color: 'darkred' });

    return () => board.unsuspendUpdate();
  }, []);

  return (
    <div>
      <h4>Куб со стороной a = 2</h4>
      <div ref={boardRef} style={{ width: '100%', height: '500px' }} />
    </div>
  );
};

export default Cube3D;