import React, {useRef, useEffect} from "react"

const KatexHtmlRenderer = ({ 
  html, 
  delimiters = [
    { left: '$$', right: '$$', display: true },
    { left: '\\[', right: '\\]', display: true },
    { left: '\\(', right: '\\)', display: false },
  ] 
}) => {
  const containerRef = useRef(null);

  useEffect(() => {
    if (!containerRef.current || !html) return;

    const container = containerRef.current;
    
    // Создаем временный элемент для работы с HTML
    const tempDiv = document.createElement('div');
    tempDiv.innerHTML = html;

    // Функция для рекурсивного обхода DOM и обработки формул
    const processNode = (node) => {
      // Если это текстовый узел, проверяем наличие формул
      if (node.nodeType === Node.TEXT_NODE) {
        const text = node.textContent;
        let processedText = text;
        let hasFormulas = false;
        
        // Создаем фрагмент для результатов
        const fragment = document.createDocumentFragment();
        
        // Обрабатываем все типы делимитеров
        delimiters.forEach(({ left, right, display }) => {
          const pattern = new RegExp(
            `(${escapeRegExp(left)}.*?${escapeRegExp(right)})`,
            'gs'
          );
          
          const parts = processedText.split(pattern);
          
          if (parts.length > 1) {
            hasFormulas = true;
            parts.forEach(part => {
              if (part.startsWith(left) && part.endsWith(right)) {
                // Извлекаем формулу
                const formula = part.substring(
                  left.length, 
                  part.length - right.length
                );
                
                try {
                  // Рендерим KaTeX
                  const span = document.createElement('span');
                  katex.render(formula, span, {
                    displayMode: display,
                    throwOnError: false,
                    errorColor: '#cc0000'
                  });
                  fragment.appendChild(span);
                } catch (error) {
                  // В случае ошибки оставляем оригинальный текст
                  const errorSpan = document.createElement('span');
                  errorSpan.style.color = '#cc0000';
                  errorSpan.textContent = part;
                  fragment.appendChild(errorSpan);
                }
              } else if (part) {
                // Обычный текст
                fragment.appendChild(document.createTextNode(part));
              }
            });
          }
        });

        if (hasFormulas) {
          // Заменяем текстовый узел на фрагмент с формулами
          node.replaceWith(fragment);
          return true;
        }
      } 
      // Если это элемент, обрабатываем его детей
      else if (node.nodeType === Node.ELEMENT_NODE) {
        // Пропускаем скрипты и стили
        if (['SCRIPT', 'STYLE'].includes(node.tagName)) {
          return false;
        }
        
        // Обрабатываем всех детей
        const children = Array.from(node.childNodes);
        let changed = false;
        
        children.forEach(child => {
          if (processNode(child)) {
            changed = true;
          }
        });
        
        return changed;
      }
      
      return false;
    };

    // Обрабатываем весь контент
    const children = Array.from(tempDiv.childNodes);
    children.forEach(child => processNode(child));
    
    // Заменяем содержимое контейнера
    container.innerHTML = '';
    children.forEach(child => container.appendChild(child.cloneNode(true)));
    
  }, [html, delimiters]);

  // Вспомогательная функция для экранирования спецсимволов в регулярках
  function escapeRegExp(string) {
    return string.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  }

  return <div ref={containerRef} />;
};

const InlineKatex = ({ formula, displayMode = false }) => {
  const ref = useRef(null);

  useEffect(() => {
    if (ref.current) {
      try {
        katex.render(formula, ref.current, {
          displayMode,
          throwOnError: false,
          errorColor: '#cc0000'
        });
      } catch (error) {
        ref.current.innerHTML = `<span style="color: #cc0000">${formula}</span>`;
      }
    }
  }, [formula, displayMode]);

  return <span ref={ref} />;
};



function createMarkup(content) {
  return {__html: content};
}

