import React, { useRef } from 'react';

import { useContext } from "react";
import { QuizContext, QuizDispatchContext } from "./QuizContext";

import QuickCalculator from "./QuickCalculator";

import useSaveRealtimeDb from './useSaveRealtimeDb';

import { Container, Form, Button, InputGroup } from "react-bootstrap";


function ContexQuizWithRandomNumber() {
    const dispatch = useContext(QuizDispatchContext);
    const { answer, randomfrom } = useContext(QuizContext);
    const { saveData, loading, error } = useSaveRealtimeDb();
    const inputRef = useRef(null);

    const handleSubmit = async (event) => {
        event.preventDefault();
        // 2. Access the input values using the .current property of the refs
        const enteredInput = inputRef.current.value;
   //     console.log(enteredInput);
   //     console.log(answer)

        const userValue = parseFloat(enteredInput);

        if (
            parseFloat(userValue) / parseFloat(answer) < 1.02 &&
            parseFloat(userValue) / parseFloat(answer) > 0.98 ||

            answer === 0 && enteredInput === "0"

        ) {
            dispatch({
                type: "SEED_STATE",
                payload: {
                    objects: {
                        isAnswered: true,
                        isCorrect: true,
                        userAnswer: userValue
                    },
                },
            });

            await saveData(userValue);
        } else {
            dispatch({
                type: "SEED_STATE",
                payload: {
                    objects: {
                        isAnswered: true,
                        isCorrect: false,
                        userAnswer: userValue
                    },
                },
            });
        }
        // event.target.reset();
    };

    return <Container>

        {!randomfrom && <QuickCalculator />}

        <Form onSubmit={handleSubmit}>


            <InputGroup size="sm" style={{ width: "95%", margin: "1rem" }} >

                <Button variant="outline-secondary" size="sm" type="submit">
                    Ответ
                </Button>


                <Form.Control
                    type="text"
                    //  placeholder="Ответ"
                    ref={inputRef} // Key step
                    required
                    aria-label="Answer"
                    aria-describedby="inputGroup-answer"
                />


            </InputGroup>


        </Form>

        {loading ? <span>...</span> : error ? <span>{":-("}</span> : null}

    </Container>
}

export default ContexQuizWithRandomNumber