
import React, { useEffect, useRef } from 'react';
//import JXG from 'jsxgraph';

const TriangularPyramid = () => {
  const boardRef = useRef(null);

  useEffect(() => {
    const board = JXG.JSXGraph.initBoard(boardRef.current, {
      boundingbox: [-1, 4, 5, -1],
      axis: true,
      grid: true,
      showNavigation: false,
      showCopyright: false
    });

    // Основание - равносторонний треугольник
    const A = board.create('point', [0, 0], { name: 'A', size: 4, color: 'blue' });
    const B = board.create('point', [3, 0], { name: 'B', size: 4, color: 'blue' });
    const C = board.create('point', [1.5, 2.598], { name: 'C', size: 4, color: 'blue' }); // 3 * √3/2
    
    // Вершина пирамиды
    const S = board.create('point', [1.5, 1.299, 2.5], { name: 'S', size: 4, color: 'red' }); // Центр + высота
    
    // Основание
    board.create('polygon', [A, B, C], {
      fillColor: 'lightblue',
      fillOpacity: 0.3,
      borders: { strokeColor: 'blue', strokeWidth: 2 }
    });

    // Боковые ребра
    [[A, S], [B, S], [C, S]].forEach(edge => {
      board.create('segment', edge, {
        strokeColor: 'red',
        strokeWidth: 2,
        dash: 1
      });
    });

    // Высота
    const H = board.create('point', [1.5, 1.299], { name: 'H', size: 3, color: 'green' });
    board.create('segment', [H, S], {
      strokeColor: 'green',
      strokeWidth: 2,
      dash: 2
    });

    // Апофема
    const M = board.create('midpoint', [A, B], { name: 'M', size: 3, color: 'orange' });
    board.create('segment', [M, S], {
      strokeColor: 'orange',
      strokeWidth: 2,
      dash: 2
    });

    // Подписи
    board.create('text', [1.5, -0.3, 'a = 3'], { fontSize: 12, color: 'darkblue' });
    board.create('text', [1.8, 1.5, 'h = 2.5'], { fontSize: 12, color: 'darkgreen' });
    board.create('text', [0.7, 0.8, 'SH = 2.5'], { fontSize: 12, color: 'darkgreen' });
    board.create('text', [2.3, 1.5, 'SM ≈ 2.69'], { fontSize: 12, color: 'darkorange' });

    return () => board.unsuspendUpdate();
  }, []);

  return (
    <div>
      <h4>Правильная треугольная пирамида (тетраэдр)</h4>
      <p>Сторона основания a = 3, высота h = 2.5</p>
      <div ref={boardRef} style={{ width: '100%', height: '500px' }} />
    </div>
  );
};

export default TriangularPyramid;