import React, { useEffect, useRef } from 'react';
import katex from 'katex';

const DoubleAngleFormulas = () => {
  const boardRef = useRef(null);

  useEffect(() => {
    const board = window.JXG.JSXGraph.initBoard(boardRef.current, {
      boundingbox: [-2, 2, 2, -2],
      axis: true,
      grid: true,
      showNavigation: false,
      showCopyright: false
    });

    const colors = {
      circle: '#6c757d',
      alpha: '#dc3545',
      doubleAlpha: '#007bff',
      construction: '#28a745'
    };

    // Единичная окружность
    board.create('circle', [[0, 0], [1, 0]], {
      strokeColor: colors.circle,
      strokeWidth: 1,
      fillColor: 'none'
    });

    const O = board.create('point', [0, 0], {
      name: '', size: 2, color: '#212529', fixed: true
    });

    // Слайдер для α
    const slider = board.create('slider', [[-1.5, -1.5], [1, -1.5], [0, 0, Math.PI]], {
      name: 'α',
      snapWidth: Math.PI / 12,
      baselineColor: colors.alpha,
      fillColor: colors.alpha + '20',
      strokeColor: colors.alpha,
      width: 8
    });

    // Точки
    const P_alpha = board.create('point', [
      () => Math.cos(slider.Value()),
      () => Math.sin(slider.Value())
    ], {
      name: 'P', size: 4, color: colors.alpha, fixed: true
    });

    const P_2alpha = board.create('point', [
      () => Math.cos(2 * slider.Value()),
      () => Math.sin(2 * slider.Value())
    ], {
      name: 'Q', size: 4, color: colors.doubleAlpha, fixed: true
    });

    // Векторы
    board.create('arrow', [O, P_alpha], {
      strokeColor: colors.alpha,
      strokeWidth: 2,
      lastArrow: true
    });

    board.create('arrow', [O, P_2alpha], {
      strokeColor: colors.doubleAlpha,
      strokeWidth: 3,
      lastArrow: true
    });

    // Проекции для вывода формулы
    // Проекция P на ось X
    const projX = board.create('segment', [P_alpha, [() => P_alpha.X(), 0]], {
      strokeColor: colors.construction,
      strokeWidth: 1,
      dash: 1
    });

    // Проекция P на ось Y
    const projY = board.create('segment', [P_alpha, [0, () => P_alpha.Y()]], {
      strokeColor: colors.construction,
      strokeWidth: 1,
      dash: 1
    });

    // Построение для sin 2α
    const P_reflected = board.create('point', [
      () => P_alpha.X(),
      () => -P_alpha.Y()
    ], {
      name: '', size: 2, color: colors.construction, fixed: true, visible: false
    });

    // Прямоугольный треугольник для иллюстрации
    const triangle = board.create('polygon', [O, P_alpha, [() => P_alpha.X(), 0]], {
      fillColor: colors.construction + '20',
      borders: { strokeColor: colors.construction, strokeWidth: 1 }
    });

    // Формулы
    const formulaBox = board.create('text', [-1.8, 1.8, ''], {
      fontSize: 14,
      color: '#212529',
      fixed: true,
      parse: false
    });

    const updateFormula = () => {
      const alpha = slider.Value();
      const sinA = Math.sin(alpha);
      const cosA = Math.cos(alpha);
      const sin2A = Math.sin(2 * alpha);
      const calc2A = 2 * sinA * cosA;
      
      const formula = `\\sin 2\\alpha = 2\\sin\\alpha\\cos\\alpha`;
      const values = `= 2·${sinA.toFixed(2)}·${cosA.toFixed(2)} = ${calc2A.toFixed(2)}`;
      const actual = `\\sin(${(2*alpha).toFixed(2)}) = ${sin2A.toFixed(2)}`;
      
      try {
        const html = katex.renderToString(formula + '\\\\' + values + '\\\\' + actual, {
          displayMode: true,
          throwOnError: false
        });
        formulaBox.setText(html);
      } catch (error) {
        formulaBox.setText(formula + '\n' + values + '\n' + actual);
      }
    };

    slider.on('drag', updateFormula);
    slider.on('up', updateFormula);
    updateFormula();

    // Подписи
    const labelAlpha = board.create('text', [
      () => Math.cos(slider.Value()) * 0.5,
      () => Math.sin(slider.Value()) * 0.5,
      'α'
    ], {
      color: colors.alpha,
      fontSize: 12,
      fixed: true
    });

    const label2Alpha = board.create('text', [
      () => Math.cos(2 * slider.Value()) * 1.1,
      () => Math.sin(2 * slider.Value()) * 1.1,
      '2α'
    ], {
      color: colors.doubleAlpha,
      fontSize: 12,
      fixed: true
    });

    const cosLabel = board.create('text', [0.5, -0.2, 'cos α'], {
      color: colors.construction,
      fontSize: 10
    });

    const sinLabel = board.create('text', [0.2, 0.5, 'sin α'], {
      color: colors.construction,
      fontSize: 10
    });

    return () => board.unsuspendUpdate();
  }, []);

  return (
    <div>
      <div ref={boardRef} style={{ height: "400px", width: "400px" }} />
      <div className="text-center mt-2">
        <small className="text-muted">Измените угол α, чтобы увидеть связь с углом 2α</small>
      </div>
    </div>
  );
};

export default DoubleAngleFormulas;