import { useReducer, useEffect } from "react";
import commonReducer from "../../features/commonReducer";

import { upsertPost } from '../../features/posts/postsSlice';

import { useSelector, useDispatch } from "react-redux";
import { selectApplication } from '../../features/application/applicationSlice';
//import useSaveRealtimeDb from './useSaveRealtimeDb';
import { selectPosts } from "../../features/posts/postsSlice";

import arraysEqual from "../../utilities/arraysEqual";

import { Container, Alert } from "react-bootstrap";
import { saveTestResult } from "./useSaveRealtimeDb";

function calculateAnswer(answer, randomValue) {
    const parser = new formulaParser.Parser();

    const processedAnswer = answer.replace(/{var1-10}/g, randomValue);

    try {
        return parser.parse(processedAnswer).result;
    } catch (error) {
        console.error(`Error evaluating answer: ${processedAnswer}`, error);
        return null;
    }
}



function ShowQuizResults() {
    let { user, email} = useSelector(selectApplication);
    const { posts } = useSelector(selectPosts);
    const [localState, localDispatch] = useReducer(
        commonReducer, {
        isLoading: true,
        userPercent: 0,
        length: 0
    });

    useEffect(() => {
        let quizesSets = window.quizesSets;

        let rightAnswers = 0;

        posts.map(post => {
            let foundItem = quizesSets.find(item => item.id === post.id);
            console.log(foundItem);

            if (Array.isArray(foundItem?.answers) && foundItem.answers.length === 1 && arraysEqual(foundItem.answers, [post?.userValue])) {
                rightAnswers++;
                console.log(foundItem + "is right")
            }

            if (Array.isArray(foundItem?.answers) && foundItem.answers.length > 1 && arraysEqual(foundItem.answers, post.userValue)) {
                rightAnswers++;
                 console.log(foundItem + "is right")
            }

            if (foundItem?.answer) {
                let answer = calculateAnswer(foundItem.answer, post.randomValue)
                if (
                    parseFloat(post?.userValue) / parseFloat(answer) < 1.02 &&
                    parseFloat(post?.userValue) / parseFloat(answer) > 0.98
                ) { rightAnswers++;  console.log(foundItem + "is right") }
            }

        })

       

        saveTestResult(
            email,
            `<div class="alert alert-primary" role="alert">
                    ${Math.round(rightAnswers*100/quizesSets.length)}% из 100% 
            </div>`,
            Math.round(rightAnswers*100/quizesSets.length) + " %",
            user, null
        ).then(() => console.log("Saved"));



        localDispatch({
            type: "SEED_STATE",
            payload: {
                objects: {
                    isLoading: false,
                    length: quizesSets.length,
                    posts: posts.length,
                    userPercent: rightAnswers*100/quizesSets.length
                },
            },
        });
    }, [])

    if (localState.isLoading) {
        return <Container>...</Container>
    }


    return <Container>
        <Alert variant={"primary"} className="m-1">
            Вы набрали {Math.round(localState.userPercent)}% из 100%
            <hr />
            Всего {localState.length}
            <hr />
            {localState.posts}
        </Alert>
    </Container>
}

export default ShowQuizResults