import React, { useEffect, useRef } from 'react';
//import JXG from 'jsxgraph';

const Parallelogram = () => {
  const boardRef = useRef(null);

  useEffect(() => {
    const board = JXG.JSXGraph.initBoard(boardRef.current, {
      boundingbox: [-2, 6, 8, -2],
      axis: true,
      grid: true,
      showNavigation: false,
      showCopyright: false
    });

    // Вершины параллелограмма ABCD
    const A = board.create('point', [0, 0], { name: 'A', size: 4, color: 'blue' });
    const B = board.create('point', [5, 0], { name: 'B', size: 4, color: 'blue' });
    const C = board.create('point', [7, 3], { name: 'C', size: 4, color: 'blue' });
    const D = board.create('point', [2, 3], { name: 'D', size: 4, color: 'blue' });

    // Стороны
    board.create('segment', [A, B], { strokeColor: 'red', strokeWidth: 2 });
    board.create('segment', [B, C], { strokeColor: 'red', strokeWidth: 2 });
    board.create('segment', [C, D], { strokeColor: 'red', strokeWidth: 2 });
    board.create('segment', [D, A], { strokeColor: 'red', strokeWidth: 2 });

    // Диагонали
    board.create('segment', [A, C], { 
      strokeColor: 'green', 
      strokeWidth: 2,
      dash: 2 
    });
    
    board.create('segment', [B, D], { 
      strokeColor: 'green', 
      strokeWidth: 2,
      dash: 2 
    });

    // Точка пересечения диагоналей
    const intersection = board.create('intersection', [A, C, B, D, 0], {
      name: 'O',
      size: 3,
      color: 'black'
    });

    // Высота
    const H = board.create('point', [0, 3], { name: 'H', size: 3, color: 'purple' });
    board.create('segment', [A, H], {
      strokeColor: 'purple',
      strokeWidth: 1,
      dash: 1
    });

    // Углы
    board.create('angle', [D, A, B], {
      radius: 0.8,
      color: 'orange',
      fillOpacity: 0.3
    });
    
    board.create('angle', [A, B, C], {
      radius: 0.8,
      color: 'orange',
      fillOpacity: 0.3
    });

    // Длины
    board.create('text', [2.5, -0.5, 'AB = 5'], { fontSize: 12, color: 'darkred' });
    board.create('text', [1, 1.5, 'AD = 3.61'], { fontSize: 12, color: 'darkred' });
    board.create('text', [-0.5, 1.5, 'h = 3'], { fontSize: 12, color: 'purple' });
    board.create('text', [3.5, 1.5, 'α ≈ 56.3°'], { fontSize: 12, color: 'orange' });

    // Свойства параллелограмма
    board.create('text', [0, 4.5, 'AO = OC, BO = OD'], { fontSize: 11, color: 'darkgreen' });

    return () => board.unsuspendUpdate();
  }, []);

  return (
    <div>
      <h3>Параллелограмм</h3>
      <div>Стороны: AB = 5, AD ≈ 3.61, высота h = 3</div>
      <div>Острый угол α ≈ 56.3°, диагонали делятся пополам</div>
      <div ref={boardRef} style={{ width: '100%', height: '450px' }} />
    </div>
  );
};

export default Parallelogram;