import React, { useState, useRef, useEffect } from 'react';

import RightTriangle345 from './RightTriangle345';
import RightTrapezoid from './RightTrapezoid';
import RegularHexagon from './RegularHexagon';
import CircleWithChords from './CircleWithChords';
import Parallelogram from './Parallelogram';

import UnitVectors from './UnitVectors';
import InteractiveUnitVectors from './InteractiveUnitVectors';

import Sphere3D from './Sphere3D';
import Cone3D from './Cone3D';
import Cylinder3D from "./Cylinder3D";
import TriangularPyramid from "./TriangularPyramid"
import RectangularPrism from "./RectangularPrism";
import Cube3D from "./Cube3D";

import PythagoreanIdentity from './PythagoreanIdentity';
import ReductionFormulas from './ReductionFormulas';
import AdditionFormulas from './AdditionFormulas';
import DoubleAngleFormulas from './DoubleAngleFormulas';
import UnitCircleValues from './UnitCircleValues';

import TrigGraphs from './TrigGraphs';
import TrigEquationSolver from './TrigEquationSolver';
import TriangleSolver from './TriangleSolver';

import GeometricDistribution from './GeometricDistribution';
import EulerDiagram from './EulerDiagram';
import PascalTriangle from './PascalTriangle';

function PrepareJSXGraph({ quizTemplate }) {
  let currentType = quizTemplate || 'triangle345';

  const renderFigure = () => {
    switch (currentType) {

      case 'geometric-distribution':
        return <GeometricDistribution />;


         case "euler-diagram":
        return <EulerDiagram />;

   case "pascal-triangle":
        return <PascalTriangle />;

        


      


      // Планиметрия
      case 'triangle345':
        return <RightTriangle345 />;
      case 'rightTrapezoid':
        return <RightTrapezoid />;
      case 'circleWithChords':
        return <CircleWithChords />;
      case 'regularHexagon':
        return <RegularHexagon />;
      case 'parallelogram':
        return <Parallelogram />;
      case 'unitVectors':
        return <UnitVectors />;
      case 'interactiveVectors':
        return <InteractiveUnitVectors />;
      
      // Стереометрия
      case 'sphere3D':
        return <Sphere3D />;
      case 'cone3D':
        return <Cone3D />;
      case 'cylinder3D':
        return <Cylinder3D />;
      case 'triangularPyramid':
        return <TriangularPyramid />;
      case 'rectangularPrism':
        return <RectangularPrism />;
      case 'cube3D':
        return <Cube3D />;

         case 'pythagoreanIdentity':
      return <PythagoreanIdentity />;
    case 'reductionFormulas':
      return <ReductionFormulas />;
    case 'additionFormulas':
      return <AdditionFormulas />;
    case 'doubleAngleFormulas':
      return <DoubleAngleFormulas />;
    case 'unitCircleValues':
      return <UnitCircleValues />;

        case 'trigGraphs':
    return <TrigGraphs />;
  case 'trigEquationSolver':
    return <TrigEquationSolver />;
  case 'triangleSolver':
    return <TriangleSolver />;
      
      default:
        return <RightTriangle345 />;
    }
  };




  return <div className="container">
    {renderFigure()}
  </div>

}

export default PrepareJSXGraph