import React, { useState, useEffect } from "react";
import katex from 'katex';

function makeHTMLFromKatex(expression, displayMode = false) {
    return katex.renderToString(expression, {
        displayMode: displayMode,
        throwOnError: false,
        output: 'html',
        strict: false
    })
}

const MathExpression = ({ expression, displayMode = false, className = "" }) => {
    const [html, setHtml] = useState('');

    useEffect(() => {
        try {
            const katexHtml = makeHTMLFromKatex(expression, displayMode)
            setHtml(katexHtml);
        } catch (error) {
            console.error('KaTeX rendering error:', error);
            setHtml(`<span class="text-danger">${expression}</span>`);
        }
    }, [expression, displayMode]);

    return <span className={className} dangerouslySetInnerHTML={{ __html: html }} />;
};


// Блочный MathExpression (с displayMode=true по умолчанию)
const BlockMathExpression = ({ expression, className = "" }) => {
    const [html, setHtml] = useState('');

    useEffect(() => {
        try {
            const katexHtml = makeHTMLFromKatex(expression, true); // displayMode=true
            setHtml(katexHtml);
        } catch (error) {
            console.error('KaTeX rendering error:', error);
            setHtml(`<div class="text-danger">${expression}</div>`);
        }
    }, [expression]);

    return <div className="katex-block-wrapper" style={{ 
    overflow: 'visible', 
    minHeight: '50px' 
  }}>
    <div className={className} dangerouslySetInnerHTML={{ __html: html }} />
  </div>
    
    // <div className={className} dangerouslySetInnerHTML={{ __html: html }} />;
};


