import React, { useEffect, useRef } from 'react';
import katex from 'katex';

const PythagoreanIdentity = () => {
  const boardRef = useRef(null);

  useEffect(() => {
    const board = window.JXG.JSXGraph.initBoard(boardRef.current, {
      boundingbox: [-2, 2, 2, -2],
      axis: true,
      grid: true,
      showNavigation: false,
      showCopyright: false
    });

    const colors = {
      circle: '#6c757d',
      point: '#dc3545',
      sine: '#007bff',
      cosine: '#28a745',
      hypotenuse: '#212529'
    };

    // Единичная окружность
    const circle = board.create('circle', [[0, 0], [1, 0]], {
      strokeColor: colors.circle,
      strokeWidth: 1,
      fillColor: 'none'
    });

    // Центр
    const O = board.create('point', [0, 0], {
      name: '', size: 2, color: colors.hypotenuse, fixed: true
    });

    // Точка на окружности (можно двигать)
    const P = board.create('point', [
      () => Math.cos(board.alpha),
      () => Math.sin(board.alpha)
    ], {
      name: 'P', size: 4, color: colors.point, fixed: false
    });

    // Начальный угол
    board.alpha = Math.PI / 4;

    // Линии-проекции
    const projX = board.create('segment', [P, [() => P.X(), 0]], {
      strokeColor: colors.cosine,
      strokeWidth: 2,
      dash: 1
    });

    const projY = board.create('segment', [P, [0, () => P.Y()]], {
      strokeColor: colors.sine,
      strokeWidth: 2,
      dash: 1
    });

    // Гипотенуза (радиус)
    const radius = board.create('segment', [O, P], {
      strokeColor: colors.hypotenuse,
      strokeWidth: 3
    });

    // Область для формулы
    const formulaBox = board.create('text', [-1.8, 1.8, ''], {
      fontSize: 16,
      color: '#212529',
      fixed: true,
      parse: false
    });

    // Обновление формулы
    const updateFormula = () => {
      const cos = Math.cos(board.alpha);
      const sin = Math.sin(board.alpha);
      const cosSquared = cos * cos;
      const sinSquared = sin * sin;
      const sum = cosSquared + sinSquared;
      
      const formula = `\\cos^2\\alpha + \\sin^2\\alpha = ${cosSquared.toFixed(2)} + ${sinSquared.toFixed(2)} = ${sum.toFixed(2)}`;
      
      try {
        const html = katex.renderToString(formula, {
          displayMode: true,
          throwOnError: false
        });
        formulaBox.setText(html);
      } catch (error) {
        formulaBox.setText(formula);
      }
    };

    // Создаем слайдер для угла
    const slider = board.create('slider', [[-1.5, -1.5], [1, -1.5], [0, 0, 2 * Math.PI]], {
      name: 'α',
      snapWidth: Math.PI / 12,
      baselineColor: 'gray',
      highlineColor: 'blue',
      fillColor: 'lightblue',
      strokeColor: 'blue',
      width: 8,
      label: { fontSize: 14 }
    });

    // Привязываем угол к слайдеру
    board.alpha = () => slider.Value();

    // Обновляем при изменении слайдера
    slider.on('drag', updateFormula);
    slider.on('up', updateFormula);

    // Инициализация формулы
    updateFormula();

    // Подписи
    const cosText = board.create('text', [0.5, -0.2, 'cos α'], {
      color: colors.cosine,
      fontSize: 12
    });

    const sinText = board.create('text', [0.2, 0.5, 'sin α'], {
      color: colors.sine,
      fontSize: 12
    });

    const radiusText = board.create('text', [0.3, 0.3, '1'], {
      color: colors.hypotenuse,
      fontSize: 12
    });

    return () => board.unsuspendUpdate();
  }, []);

  return (
    <div>
      <div ref={boardRef} style={{ height: "400px", width: "400px" }} />
      <div className="text-center mt-2">
        <small className="text-muted">Перемещайте слайдер для изменения угла α</small>
      </div>
    </div>
  );
};

export default PythagoreanIdentity;