import React, { useEffect, useRef } from 'react';
//import JXG from 'jsxgraph';

const Sphere3D = () => {
  const boardRef = useRef(null);

  useEffect(() => {
    const board = JXG.JSXGraph.initBoard(boardRef.current, {
      boundingbox: [-4, 4, 4, -4],
      axis: false,
      grid: false,
      showNavigation: false,
      showCopyright: false
    });

    // Центр сферы
    const O = board.create('point', [0, 0], { name: 'O', size: 4, color: 'black' });
    
    // Основная окружность
    const circle = board.create('circle', [O, 3], {
      strokeColor: 'blue',
      strokeWidth: 2,
      fillColor: 'lightblue',
      fillOpacity: 0.1
    });

    // Радиусы в разных направлениях
    const points = [];
    for (let i = 0; i < 8; i++) {
      const angle = (i * 45 * Math.PI) / 180;
      const x = 3 * Math.cos(angle);
      const y = 3 * Math.sin(angle);
      const point = board.create('point', [x, y], { 
        size: 3, 
        color: 'red',
        name: ''
      });
      points.push(point);
      
      // Радиус
      board.create('segment', [O, point], {
        strokeColor: 'red',
        strokeWidth: 1,
        dash: 1,
        opacity: 0.5
      });
    }

    // Диаметр
    const A = points[0];
    const B = points[4]; // Противоположная точка
    board.create('segment', [A, B], {
      strokeColor: 'purple',
      strokeWidth: 2,
      dash: 2
    });

    // Подписи
    board.create('text', [1.5, 1.5, 'R = 3'], { fontSize: 14, color: 'darkblue' });
    board.create('text', [0, -0.5, 'O'], { fontSize: 12, color: 'black' });
    board.create('text', [3.3, 0.1, 'A'], { fontSize: 12, color: 'red' });
    board.create('text', [-3.3, 0.1, 'B'], { fontSize: 12, color: 'red' });

    // Формулы
    board.create('text', [-3.8, 3.5, 'V = ⁴/₃πR³ = ⁴/₃π·27 = 36π'], {
      fontSize: 14,
      color: 'darkgreen',
      anchorX: 'left'
    });

    return () => board.unsuspendUpdate();
  }, []);

  return (
    <div>
      <h4>Сфера: R = 3</h4>
      <div ref={boardRef} style={{ width: '100%', height: '500px' }} />
    </div>
  );
};

export default Sphere3D;