export async function updateFirebaseNode(updates = { temp: "temp" }) {
    try {
        //let res = await timeout(3000); console.log(updates);
        await update(ref(db), updates);
        return true
    }
    catch (error) {
        console.error(error)
        return error
    }
}

export function getFirebaseNodeKey(url) {
    return push(child(ref(db), url + "/")).key;
}

export async function saveQuizResult(email, quiz, calculatedAnswer = "", processedText = "", user, avatarUrl = null) {

    let updates = {};
    if (email.length > 6) {
        let userEmail = email.replace(/[^a-zA-Z0-9]/g, "_")
        let idPost = getFirebaseNodeKey("usersCraft/" + userEmail + "/posts");
        let currentDay = new Intl.DateTimeFormat("en", {
            weekday: "short",
            year: "numeric",
            month: "short",
            day: "numeric",
        })
            .format(new Date())
            .replace(/[^a-zA-Z0-9]/g, "_");

        let postObject = {
            id: idPost, //Math.floor(Math.random() * 1001),
            title: quiz.title,
            theme: quiz.theme,
            answer: calculatedAnswer,
            comment: quiz?.hint ? quiz.hint : quiz.title + " (" + quiz.theme + ")",
            type: "spreadsheet",
            content: {},
            quizString: processedText,
            deleted: false,
            email: email,
            user: user,
            avatarUrl: !!avatarUrl ? avatarUrl : null,
            date: new Intl.DateTimeFormat("ru", {
                weekday: "short",
                year: "numeric",
                month: "short",
                day: "numeric",
                hour: "numeric",
                minute: "numeric",
            }).format(new Date()), //Date().toJSON()
        };

        let currentDayObject = {
            id: idPost,
            title: quiz.title,
            theme: quiz.theme,
            email: email,
            user: user,
            avatarUrl: !!avatarUrl ? avatarUrl : null,
            timestamp: +Date.now(),
        };

        //  dispatch(upsertPost(postObject));

        updates["/usersCraft/" + userEmail + "/posts/" + idPost] = postObject;
        updates[
            "/currentDayMath/" + currentDay + "/posts/" + idPost
        ] = currentDayObject;

        if (quiz?.altpath === "currentDay") {
             updates[
            "/currentDay/" + currentDay + "/posts/" + idPost
        ] = currentDayObject;
        }

        updateFirebaseNode(updates);
    }

}

const useMathQuiz = (quiz) => {
    const { email, user, avatarUrl } = useSelector(selectApplication);
    let dispatch = useDispatch();

    // const [questionState, setQuestionState] = useReducer(commonReducer, {
    //     userAnswer: '',
    //     isAnswered: false,
    //     isCorrect: null,
    //     showHint: false,
    //     resultMessage: '',
    //     randomValue: null,
    //     calculatedAnswer: null,
    //     processedText: '',
    //     processedAnswer: '',
    //     userAnswers: [],
    //     isExam: document.body.dataset?.exam
    // });

    const [questionState, setQuestionState] = useState({
        userAnswer: '',
        isAnswered: false,
        isCorrect: null,
        showHint: false,
        resultMessage: '',
        randomValue: null,
        calculatedAnswer: null,
        processedText: '',
        processedAnswer: '',
        userAnswers: [],
        isExam: document.body.dataset?.exam
    });



    useEffect(() => {

        //  console.log(quiz);

        let randomValue;
        if (quiz.randomfrom && Array.isArray(quiz.randomfrom)) {
            const randomIndex = Math.floor(Math.random() * quiz.randomfrom.length);
            randomValue = quiz.randomfrom[randomIndex];
        } else {
            randomValue = Math.floor(Math.random() * 10) + 1;
        }



        if (quiz?.type === "mathwithrandomnumber") {
            let processedHint = "";
            if (!!quiz?.hint && quiz.hint.includes("{var1-10}")) {
                processedHint = quiz.hint;
                const searchRegExp = /{var1-10}/g;
                const replaceWith = randomValue.toString();
                processedHint = processedHint.replace(searchRegExp, replaceWith);

                if (processedHint.includes("{=")) {
                    let stringExtractor = extract(["{=", "}"]);
                    let stuffIneed = stringExtractor(processedHint);
                    for (let i = 0; i < stuffIneed.length; i++) {
                        let feedback = Math.round(parser.parse(stuffIneed[i]).result * 1000) / 1000;
                        processedHint = processedHint.replace("{=" + stuffIneed[i] + "}", feedback);
                    }
                }
            } else {
                processedHint = quiz?.hint
            }

            //      console.log(processedHint)

            let processedText = ""; //quiz.text.replace(/{var1-10}/g, randomValue);

            if (!!quiz?.text) {
                processedText = quiz.text;
                const searchRegExp = /{var1-10}/g;
                const replaceWith = randomValue.toString();
                processedText = processedText.replace(searchRegExp, replaceWith);

                if (processedText.includes("{=")) {
                    let stringExtractor = extract(["{=", "}"]);
                    let stuffIneed = stringExtractor(processedText);
                    for (let i = 0; i < stuffIneed.length; i++) {
                        let feedback = Math.round(parser.parse(stuffIneed[i]).result * 1000) / 1000;
                        processedText = processedText.replace("{=" + stuffIneed[i] + "}", feedback);
                    }
                }
            }

            const processedAnswer = quiz.answer.replace(/{var1-10}/g, randomValue);
            let calculatedAnswer
            try {
                calculatedAnswer = parser.parse(processedAnswer);
            } catch (error) {
                console.error(`Error evaluating answer: ${processedAnswer}`, error);
                return null;
            }

            //   console.log(calculatedAnswer);

           

            setQuestionState(prev => ({
                ...prev,
                randomValue: randomValue,
                processedText: processedText,
                processedAnswer: processedAnswer,
                processedHint: processedHint,
                calculatedAnswer: calculatedAnswer.result
            }));
        }


        if (quiz?.type === "quizwithrandomnumber") {

            let processedHint = "";
            if (!!quiz?.hint) {
                processedHint = quiz.hint;
                const searchRegExp = /{var1-10}/g;
                const replaceWith = randomValue.toString();
                processedHint = processedHint.replace(searchRegExp, replaceWith);

                let stringExtractor = extract(["{=", "}"]);
                let stuffIneed = stringExtractor(processedHint);

                for (let i = 0; i < stuffIneed.length; i++) {
                    let feedback = Math.round(parser.parse(stuffIneed[i]).result * 1000) / 1000;
                    processedHint = processedHint.replace("{=" + stuffIneed[i] + "}", feedback);
                }
            }





            let quizString = quiz.text;
            const searchRegExp = /{var1-10}/g;
            const replaceWith = randomValue.toString();
            quizString = quizString.replace(searchRegExp, replaceWith);

            let answer = quiz.answer.replace(searchRegExp, replaceWith);
            answer = Math.round(parser.parse(answer).result * 1000) / 1000;

            let stringExtractor = extract(["{=", "}"]);
            let stuffIneed = stringExtractor(quizString);

            for (let i = 0; i < stuffIneed.length; i++) {
                let feedback = Math.round(parser.parse(stuffIneed[i]).result * 1000) / 1000;
                quizString = quizString.replace("{=" + stuffIneed[i] + "}", feedback);
            }

              setQuestionState(prev => ({
                ...prev,
                randomValue: randomValue,
                processedText: quizString,
                processedHint: processedHint,
                calculatedAnswer: answer
            }));
        }


    }, [quiz?.id])

    function updateUserAnswers(userAnswers) {
        setQuestionState({
            type: "SET_STORE_OBJECT",
            payload: {
                key: "userAnswers",
                value: userAnswers
            },
        });
    }

    const handleCheckboxChange = useCallback((item, isChecked) => {
        console.log(item, isChecked);

        console.log(questionState.userAnswers);
        //   console.log([...questionState.userAnswers, item]);

        if (isChecked) {

            // let newUserAnaswers = [...questionState.userAnswers, item];
            // console.log(newUserAnaswers);
            // newUserAnaswers.push(item)
            // setQuestionState({
            //     type: "SET_STORE_OBJECT",
            //     payload: {
            //         key: "userAnswers",
            //         value: newUserAnaswers
            //     },
            // });


            setQuestionState(prev => ({
                ...prev,
                userAnswers: [...questionState.userAnswers, item]
            }));
        } else {

   
            setQuestionState(prev => ({
                ...prev,
                userAnswers: [...questionState.userAnswers.filter(answer => answer !== item)]
            }));
        }
    }, [])



    // 5. Обработчики событий
    const handleAnswerChange = useCallback((answer) => {
           setQuestionState(prev => ({
                    ...prev,
                    userAnswer: answer                    
                }));
    }, []);


    const handleCheckAnswer = useCallback(() => {
        const { userAnswer, calculatedAnswer, processedText, randomValue, userAnswers } = questionState;

        let isCorrect = false;
        let message

        if (!userAnswer) return;

        if (quiz?.type === "mathwithrandomnumber" || quiz?.type === "quizwithrandomnumber") {
            const userValue = parseFloat(userAnswer);

            if (isNaN(userValue)) {
                setQuestionState(prev => ({
                    ...prev,
                    resultMessage: "Ответ должен быть числом",
                    isCorrect: false,
                    isAnswered: true
                }));

                return;
            }

            if (
                parseFloat(userValue) / parseFloat(calculatedAnswer) < 1.02 &&
                parseFloat(userValue) / parseFloat(calculatedAnswer) > 0.98 || calculatedAnswer === 0
            ) {
               
                isCorrect = true
                message = isCorrect ? "Правильно!" : `Неправильно. Правильный ответ: ${calculatedAnswer}`;

           
                setQuestionState(prev => ({
                    ...prev,
                    isAnswered: true,
                    isCorrect,
                    resultMessage: message
                }));

                saveQuizResult(email, quiz, calculatedAnswer, processedText, user).then(() => {
                    if (questionState.isExam) {
                        dispatch(upsertPost({
                            quizId: quiz.id,
                            id: questionState.isExam ? quiz.id : nanoid(),
                            timestamp: Date.now(),
                            //   isCorrect: true,
                            userValue,
                            randomValue
                        }))
                    }
                });

            } else {
                setQuestionState(prev => ({
                    ...prev,
                    isAnswered: true,
                    isCorrect: false,
                    resultMessage: "Неправильно"
                }));

                if (questionState.isExam) {
                    dispatch(upsertPost({
                        id: questionState.isExam ? quiz.id : nanoid(),
                        quizId: quiz.id,
                        timestamp: Date.now(),
                        userValue,
                        randomValue
                    }))
                }
            }
        }
    }, [questionState.userAnswer, questionState.calculatedAnswer]);

    return {
        // Состояние
        ...questionState,
        processedText: questionState.processedText, // || initializedQuestion.processedText,
        processedAnswer: questionState.processedAnswer, // || initializedQuestion.processedAnswer,
        randomValue: questionState.randomValue, //|| initializedQuestion.randomValue,
        calculatedAnswer: questionState.calculatedAnswer, //|| initializedQuestion.calculatedAnswer,
        userAnswers: questionState.userAnswers,
        // Обработчики
        handleAnswerChange,
        handleCheckAnswer,
        handleCheckboxChange,
        updateUserAnswers
    };
};

export default useMathQuiz