import React, { useEffect, useRef } from 'react';
//import JXG from 'jsxgraph';

const RegularHexagon = () => {
  const boardRef = useRef(null);

  useEffect(() => {
    const board = JXG.JSXGraph.initBoard(boardRef.current, {
      boundingbox: [-5, 5, 5, -5],
      axis: true,
      grid: true,
      showNavigation: false,
      showCopyright: false
    });

    // Центр шестиугольника
    const O = board.create('point', [0, 0], { name: 'O', size: 4, color: 'black' });
    
    // Радиус описанной окружности
    const R = 3;
    
    // Вершины правильного шестиугольника
    const vertices = [];
    for (let i = 0; i < 6; i++) {
      const angle = (i * 60 * Math.PI) / 180;
      const x = R * Math.cos(angle);
      const y = R * Math.sin(angle);
      const point = board.create('point', [x, y], { 
        name: String.fromCharCode(65 + i), 
        size: 4, 
        color: 'blue' 
      });
      vertices.push(point);
    }

    // Стороны шестиугольника
    for (let i = 0; i < 6; i++) {
      board.create('segment', [vertices[i], vertices[(i + 1) % 6]], {
        strokeColor: 'red',
        strokeWidth: 2
      });
    }

    // Диагонали
    board.create('segment', [vertices[0], vertices[2]], {
      strokeColor: 'green',
      strokeWidth: 2,
      dash: 2
    });
    
    board.create('segment', [vertices[0], vertices[3]], {
      strokeColor: 'orange',
      strokeWidth: 2,
      dash: 2
    });

    // Описанная окружность
    board.create('circle', [O, R], {
      strokeColor: 'lightblue',
      strokeWidth: 1,
      dash: 1
    });

    // Углы
    board.create('angle', [vertices[5], vertices[0], vertices[1]], {
      radius: 0.8,
      color: 'purple',
      fillOpacity: 0.3
    });

    // Длины
    board.create('text', [1.5, 2.5, 'R = 3'], { fontSize: 12, color: 'darkblue' });
    board.create('text', [2.5, 0.5, 'a = R = 3'], { fontSize: 12, color: 'darkred' });
    board.create('text', [0, -0.5, '120°'], { fontSize: 12, color: 'purple' });

    // Центральный угол
    board.create('angle', [vertices[0], O, vertices[1]], {
      radius: 1.5,
      color: 'green',
      fillOpacity: 0.2
    });
    board.create('text', [1, 0.5, '60°'], { fontSize: 12, color: 'darkgreen' });

    return () => board.unsuspendUpdate();
  }, []);

  return (
    <div>
      <h3>Правильный шестиугольник</h3>
      <div>Сторона a = 3, радиус описанной окружности R = 3</div>
      <div>Внутренний угол: 120°, центральный угол: 60°</div>
      <div ref={boardRef} style={{ width: '100%', height: '500px' }} />
    </div>
  );
};

export default RegularHexagon;