import React, { useEffect, useRef } from 'react';
import katex from 'katex';

const AdditionFormulas = () => {
  const boardRef = useRef(null);

  useEffect(() => {
    const board = window.JXG.JSXGraph.initBoard(boardRef.current, {
      boundingbox: [-2, 2, 2, -2],
      axis: true,
      grid: true,
      showNavigation: false,
      showCopyright: false
    });

    const colors = {
      circle: '#6c757d',
      alpha: '#dc3545',
      beta: '#007bff',
      sum: '#28a745',
      construction: '#ffc107'
    };

    // Единичная окружность
    board.create('circle', [[0, 0], [1, 0]], {
      strokeColor: colors.circle,
      strokeWidth: 1,
      fillColor: 'none'
    });

    const O = board.create('point', [0, 0], {
      name: '', size: 2, color: '#212529', fixed: true
    });

    // Слайдеры для углов
    const sliderAlpha = board.create('slider', [[-1.5, -1.5], [-0.5, -1.5], [0, 0, Math.PI]], {
      name: 'α',
      snapWidth: Math.PI / 12,
      baselineColor: colors.alpha,
      fillColor: colors.alpha + '20',
      strokeColor: colors.alpha,
      width: 6
    });

    const sliderBeta = board.create('slider', [[0.5, -1.5], [1.5, -1.5], [0, 0, Math.PI]], {
      name: 'β',
      snapWidth: Math.PI / 12,
      baselineColor: colors.beta,
      fillColor: colors.beta + '20',
      strokeColor: colors.beta,
      width: 6
    });

    // Точки на окружности
    const P_alpha = board.create('point', [
      () => Math.cos(sliderAlpha.Value()),
      () => Math.sin(sliderAlpha.Value())
    ], {
      name: '', size: 3, color: colors.alpha, fixed: true
    });

    const P_beta = board.create('point', [
      () => Math.cos(sliderBeta.Value()),
      () => Math.sin(sliderBeta.Value())
    ], {
      name: '', size: 3, color: colors.beta, fixed: true
    });

    const P_sum = board.create('point', [
      () => Math.cos(sliderAlpha.Value() + sliderBeta.Value()),
      () => Math.sin(sliderAlpha.Value() + sliderBeta.Value())
    ], {
      name: '', size: 4, color: colors.sum, fixed: true
    });

    // Векторы
    board.create('arrow', [O, P_alpha], {
      strokeColor: colors.alpha,
      strokeWidth: 2,
      lastArrow: true
    });

    board.create('arrow', [O, P_beta], {
      strokeColor: colors.beta,
      strokeWidth: 2,
      lastArrow: true
    });

    board.create('arrow', [O, P_sum], {
      strokeColor: colors.sum,
      strokeWidth: 3,
      lastArrow: true
    });

    // Геометрическое построение
    // Проекции для формулы
    const proj1 = board.create('segment', [P_alpha, [
      () => P_alpha.X() * Math.cos(sliderBeta.Value()),
      () => P_alpha.X() * Math.sin(sliderBeta.Value())
    ]], {
      strokeColor: colors.construction,
      strokeWidth: 1,
      dash: 2
    });

    const proj2 = board.create('segment', [[
      () => P_alpha.X() * Math.cos(sliderBeta.Value()),
      () => P_alpha.X() * Math.sin(sliderBeta.Value())
    ], P_sum], {
      strokeColor: colors.construction,
      strokeWidth: 1,
      dash: 2
    });

    // Формула
    const formulaBox = board.create('text', [-1.8, 1.8, ''], {
      fontSize: 14,
      color: '#212529',
      fixed: true,
      parse: false
    });

    const updateFormula = () => {
      const alpha = sliderAlpha.Value();
      const beta = sliderBeta.Value();
      
      const sinA = Math.sin(alpha);
      const cosA = Math.cos(alpha);
      const sinB = Math.sin(beta);
      const cosB = Math.cos(beta);
      
      const leftSide = Math.sin(alpha + beta);
      const rightSide = sinA * cosB + cosA * sinB;
      
      const formula = `\\sin(\\alpha+\\beta) = \\sin\\alpha\\cos\\beta + \\cos\\alpha\\sin\\beta`;
      const values = `= ${sinA.toFixed(2)}·${cosB.toFixed(2)} + ${cosA.toFixed(2)}·${sinB.toFixed(2)} = ${leftSide.toFixed(2)}`;
      
      try {
        const html = katex.renderToString(formula + '\\\\' + values, {
          displayMode: true,
          throwOnError: false
        });
        formulaBox.setText(html);
      } catch (error) {
        formulaBox.setText(formula + '\n' + values);
      }
    };

    sliderAlpha.on('drag', updateFormula);
    sliderAlpha.on('up', updateFormula);
    sliderBeta.on('drag', updateFormula);
    sliderBeta.on('up', updateFormula);
    
    updateFormula();

    // Подписи
    const labelAlpha = board.create('text', [0.7, 0.7, 'α'], {
      color: colors.alpha,
      fontSize: 12
    });

    const labelBeta = board.create('text', [0.5, 0.3, 'β'], {
      color: colors.beta,
      fontSize: 12
    });

    const labelSum = board.create('text', [
      () => Math.cos(sliderAlpha.Value() + sliderBeta.Value()) * 1.1,
      () => Math.sin(sliderAlpha.Value() + sliderBeta.Value()) * 1.1,
      'α+β'
    ], {
      color: colors.sum,
      fontSize: 12,
      fixed: true
    });

    return () => board.unsuspendUpdate();
  }, []);

  return (
    <div>
      <div ref={boardRef} style={{ height: "400px", width: "400px" }} />
      <div className="text-center mt-2">
        <small className="text-muted">Измените углы α и β, чтобы увидеть геометрический вывод формулы</small>
      </div>
    </div>
  );
};

export default AdditionFormulas;