import React, { useEffect, useRef } from 'react';
//import JXG from 'jsxgraph';

const RightTrapezoid = () => {
  const boardRef = useRef(null);

  useEffect(() => {
    const board = JXG.JSXGraph.initBoard(boardRef.current, {
      boundingbox: [-2, 5, 10, -2],
      axis: true,
      grid: true,
      showNavigation: false,
      showCopyright: false
    });

    // Вершины прямоугольной трапеции ABCD (AB || CD, ∠A = 90°, ∠B = 90°)
    // A(0,0), B(6,0), C(4,3), D(0,3)
    const A = board.create('point', [0, 0], { name: 'A', size: 4, color: 'blue' });
    const B = board.create('point', [6, 0], { name: 'B', size: 4, color: 'blue' });
    const C = board.create('point', [4, 3], { name: 'C', size: 4, color: 'blue' });
    const D = board.create('point', [0, 3], { name: 'D', size: 4, color: 'blue' });

    // Основания и боковые стороны
    board.create('segment', [A, B], { strokeColor: 'red', strokeWidth: 2 }); // Нижнее основание
    board.create('segment', [D, C], { strokeColor: 'red', strokeWidth: 2 }); // Верхнее основание
    board.create('segment', [A, D], { strokeColor: 'green', strokeWidth: 2 }); // Левая боковая (высота)
    board.create('segment', [B, C], { strokeColor: 'blue', strokeWidth: 2 }); // Правая боковая

    // Прямой угол в A
    board.create('angle', [B, A, D], { radius: 0.7, color: 'green', fillOpacity: 0.3 });
    
    // Прямой угол в B (если нужна)
    // board.create('angle', [A, B, C], { radius: 0.7, color: 'green', fillOpacity: 0.3 });

    // Длины сторон
    board.create('text', [3, -0.5, 'AB = 6'], { fontSize: 12, color: 'darkred' });
    board.create('text', [2, 1.5, 'DC = 4'], { fontSize: 12, color: 'darkred' });
    board.create('text', [-0.7, 1.5, 'AD = 3'], { fontSize: 12, color: 'darkgreen' });
    
    // Высота
    board.create('text', [3, 3.5, 'Высота h = 3'], { fontSize: 12, color: 'purple' });

    // Средняя линия
    // const M = board.create('point', [3, 0], { name: '', size: 2, color: 'gray' });
    // const N = board.create('point', [2, 3], { name: '', size: 2, color: 'gray' });
    // board.create('segment', [M, N], { 
    //   strokeColor: 'orange', 
    //   strokeWidth: 2,
    //   dash: 2 
    // });
    // board.create('text', [2.5, 1.5, 'Ср. линия = 5'], { fontSize: 11, color: 'orange' });

    return () => board.unsuspendUpdate();
  }, []);

  return (
    <div>
      <h3>Прямоугольная трапеция</h3>
      <div>Основания: AB = 6, DC = 4, высота AD = 3</div>
      <div ref={boardRef} style={{ width: '100%', height: '400px' }} />
    </div>
  );
};

export default RightTrapezoid;