 import React, { useEffect, useRef } from 'react';
//import JXG from 'jsxgraph';

const RectangularPrism = () => {
  const boardRef = useRef(null);

  useEffect(() => {
    const board = JXG.JSXGraph.initBoard(boardRef.current, {
      boundingbox: [-1, 5, 6, -1],
      axis: true,
      grid: true,
      showNavigation: false,
      showCopyright: false
    });

    // Вершины основания
    const A = board.create('point', [0, 0], { name: 'A', size: 4, color: 'blue' });
    const B = board.create('point', [4, 0], { name: 'B', size: 4, color: 'blue' });
    const D = board.create('point', [0, 3], { name: 'D', size: 4, color: 'blue' });
    const C = board.create('point', [4, 3], { name: 'C', size: 4, color: 'blue' });
    
    // Верхние вершины
    const A1 = board.create('point', [0.8, 3.8], { name: "A'", size: 4, color: 'red' });
    const B1 = board.create('point', [4.8, 3.8], { name: "B'", size: 4, color: 'red' });
    const D1 = board.create('point', [0.8, 6.8], { name: "D'", size: 4, color: 'red' });
    const C1 = board.create('point', [4.8, 6.8], { name: "C'", size: 4, color: 'red' });

    // Основания
    board.create('polygon', [A, B, C, D], {
      fillColor: 'lightblue',
      fillOpacity: 0.3,
      borders: { strokeColor: 'blue', strokeWidth: 2 }
    });

    board.create('polygon', [A1, B1, C1, D1], {
      fillColor: 'lightcoral',
      fillOpacity: 0.3,
      borders: { strokeColor: 'red', strokeWidth: 2 }
    });

    // Боковые ребра
    [[A, A1], [B, B1], [C, C1], [D, D1]].forEach(edge => {
      board.create('segment', edge, {
        strokeColor: 'green',
        strokeWidth: 2,
        dash: 1
      });
    });

    // Диагонали
    board.create('segment', [A, C1], {
      strokeColor: 'purple',
      strokeWidth: 2,
      dash: 2
    });

    // Подписи размеров
    board.create('text', [2, -0.3, 'a = 4'], { fontSize: 12, color: 'darkblue' });
    board.create('text', [4.3, 1.5, 'b = 3'], { fontSize: 12, color: 'darkblue' });
    board.create('text', [2.8, 5.3, 'h = 3'], { fontSize: 12, color: 'darkred' });

    // Формулы
    board.create('text', [0, 7.5, 'V = a·b·h = 4·3·3 = 36'], {
      fontSize: 14,
      color: 'darkgreen',
      anchorX: 'left'
    });

    return () => board.unsuspendUpdate();
  }, []);

  return (
    <div>
      <h4>Прямоугольный параллелепипед: a=4, b=3, h=3</h4>
      <div ref={boardRef} style={{ width: '100%', height: '550px' }} />
    </div>
  );
};

export default RectangularPrism;