import React, { useRef, useEffect, useState, useReducer } from 'react';
import { Container } from "react-bootstrap";
import caseReducer from '../../features/case/caseReducer';

// function JSXFunctionGraph({
//     functionType, func
// }) {
//     console.log(functionType, func)
//     return <Container>
//         JSXFunctionGraph
//     </Container>
// }

const areEqual = (a, b) => 
  a.length === b.length && a.every((val, index) => val === b[index]);


const JSXFunctionGraph = ({
  functionType: functionName,
  func,
  scriptUrl,
  boardConfig,
  style }) => {
  const boardRef = useRef(null);

  const [state, localDispatch] = useReducer(caseReducer, {
    error: null,
    loading: true
  })


  // const [error, setError] = useState(null);
  // const [loading, setLoading] = useState(true);

  useEffect(() => {
    let board = null;
    let scriptElement = null;

    const initBoard = () => {
      try {
     board = JXG.JSXGraph.initBoard(boardRef.current, {
          boundingbox: [-2, 5, 5, -2],
          axis: true,
          grid: true,
          showNavigation: false,
          showCopyright: false,
          ...boardConfig // позволяем переопределять конфигурацию
        });
        // Проверяем, доступна ли функция из глобальной области
        if (window[functionName] && typeof window[functionName] === 'function') {
          // Вызываем функцию с доской и JXG
          let props = window[functionName](board, JXG);        
          if (!areEqual(props.boardConfig.boundingbox, [-2, 5, 5, -2] ))  {
            board.setBoundingBox(props.boardConfig.boundingbox);
            console.log(props);
          }




          
        } else {
          localDispatch({
            type: "SEED_STATE",
            payload: {
              objects: {
                error: `Функция ${functionName} не найдена`
              }

            }
          })
          //  setError(`Функция ${functionName} не найдена`);
        }




      } catch (err) {
        localDispatch({
          type: "SEED_STATE",
          payload: {
            objects: {
              error: err.message
            }

          }
        })

        // setError(err.message);
      } finally {
        localDispatch({
          type: "SEED_STATE",
          payload: {
            objects: {
              loading: false
            }

          }
        })
        // setLoading(false);
      }
    };

    // Загружаем внешний скрипт
    if (scriptUrl) {
      scriptElement = document.createElement('script');
      scriptElement.src = scriptUrl;
      scriptElement.async = true;

      scriptElement.onload = () => {
        initBoard();
      };

      scriptElement.onerror = () => {
        localDispatch({
          type: "SEED_STATE",
          payload: {
            objects: {
              error: `Не удалось загрузить скрипт: ${scriptUrl}`,
              loading: false
            }

          }
        })
        //  setError(`Не удалось загрузить скрипт: ${scriptUrl}`);
        //  setLoading(false);
      };

      document.body.appendChild(scriptElement);
    } else {
      // Если нет URL скрипта, просто инициализируем доску
      initBoard();
    }

    // Очистка
    return () => {
      if (scriptElement && scriptElement.parentNode) {
        document.body.removeChild(scriptElement);
      }
      if (board) {
        board.unsuspendUpdate();
      }
    };
  }, [scriptUrl, functionName, boardConfig]);

  console.log(func, functionName)

  return (
    <div style={{ width: '100%', maxWidth: '600px', margin: '20px auto', ...style }}>
      {state?.loading && <div>Загрузка графика...</div>}
      {state?.error && <div style={{ color: 'red' }}>Ошибка: {state?.error}</div>}
      <div
        ref={boardRef}
        style={{
          width: '100%',
          height: '500px',
          border: '1px solid #ccc',
          borderRadius: '5px',
          display: state?.loading ? 'none' : 'block'
        }}
      />
    </div>
  );
};


export default JSXFunctionGraph