import React, { useReducer } from "react";
import { QuizContext, QuizDispatchContext } from "./QuizContext";

import { Card } from "react-bootstrap";

import FunctionGraph from "../FunctionGraph";
import ThreeJSViewer from "../ThreeJSViewer";
import PrepareJSXGraph from "../PrepareJSXGraph"

import shuffle from "../../utilities/shuffle";
import extract from "../../utilities/extract";

import ProcessKatex from "./ProcessKatex";


import QuizTextWithKatexAndRandom from "./QuizTextWithKatexAndRandom";

import ContextMultipleChoicesQuiz from "./ContextMultipleChoicesQuiz";
import ContextOneChoiceQuiz from "./ContextOneChoiceQuiz";
import ContexQuizWithRandomNumber from "./ContexQuizWithRandomNumber";

import commonReducer from "../../features/commonReducer";
import QuizFeedback from "./QuizFeedback";

import JSXFunctionGraph from "../JSXFunctionGraph";



function generateRandomValue(quiz) {

    let randomValue = null;
    let text = quiz?.text;
    let hint = quiz?.hint;
    let answer = quiz?.answer;

    const parser = new formulaParser.Parser();

    if (quiz?.text.includes("var1-10")) {

        if (quiz.randomfrom && Array.isArray(quiz.randomfrom)) {
            const randomIndex = Math.floor(Math.random() * quiz.randomfrom.length);
            randomValue = quiz.randomfrom[randomIndex];
        } else {
            randomValue = (Math.floor((Math.random() * 100))) / 10 + 1;
        }


        const searchRegExp = /{var1-10}/g;
        const replaceWith = randomValue.toString();
        text = text.replace(searchRegExp, replaceWith);

        if (text.includes("{=")) {
            let stringExtractor = extract(["{=", "}"]);
            let stuffIneed = stringExtractor(text);
            for (let i = 0; i < stuffIneed.length; i++) {
                let feedback = Math.round(parser.parse(stuffIneed[i]).result * 1000) / 1000;
                text = text.replace("{=" + stuffIneed[i] + "}", feedback);
            }
        }


        const processedAnswer = answer.replace(/{var1-10}/g, randomValue);

        try {
            answer = parser.parse(processedAnswer).result;
        } catch (error) {
            console.error(`Error evaluating answer: ${processedAnswer}`, error);
            return null;
        }
    }

    if (quiz?.hint.includes("var1-10")) {

        // if (quiz.randomfrom && Array.isArray(quiz.randomfrom)) {
        //     const randomIndex = Math.floor(Math.random() * quiz.randomfrom.length);
        //     randomValue = quiz.randomfrom[randomIndex];
        // } else {
        //     randomValue = Math.floor(Math.random() * 10) + 1;
        // }


        const searchRegExp = /{var1-10}/g;
        const replaceWith = randomValue.toString();
        hint = hint.replace(searchRegExp, replaceWith);

        if (hint.includes("{=")) {
            let stringExtractor = extract(["{=", "}"]);
            let stuffIneed = stringExtractor(hint);
            for (let i = 0; i < stuffIneed.length; i++) {
                let feedback = Math.round(parser.parse(stuffIneed[i]).result * 1000) / 1000;
                hint = hint.replace("{=" + stuffIneed[i] + "}", feedback);
            }
        }



    }



    return { randomValue, text, answer, hint }
}




function QuizCardWithStorage(quiz) {
    const [quizState, dispatch] = useReducer(
        commonReducer,
        {
            ...quiz,
            choices: Array.isArray(quiz?.choices) ? [...shuffle(quiz.choices)] : null,
            selectedAnswers: [],
            isAnswered: false,
            isCorrect: false,
            resultMessage: "",
            isExam: !!document.body.dataset?.exam ? true : false,
            userAnswer: null,
            ...generateRandomValue(quiz)

        }
    );


    function chooseQuizType(quiz) {

        // console.log(quiz)

        if (Array.isArray(quiz?.choices) && quiz.answers.length === 1) {
            return <ContextOneChoiceQuiz key={quiz.id} quiz={quiz} />
        }

        if (Array.isArray(quiz?.choices) && quiz.choices.length > 1) {
            return <ContextMultipleChoicesQuiz key={quiz.id} quiz={quiz} />
        }

        if (!!quiz?.answer) {
            return <ContexQuizWithRandomNumber key={quiz.id} answer={quizState.answer} />
        }

        return null
    }

    // console.log(quizState);

    return <Card bg={"light"} style={{ width: "95%", margin: "1rem" }} key={quiz.id}>
        <QuizContext.Provider value={quizState}>
            <QuizDispatchContext.Provider value={dispatch}>

                <Card.Header>{quiz.header}</Card.Header>
                <Card.Body>
                    <Card.Title>{!!quiz?.setId ? quiz.setId : ""} {quiz.title}</Card.Title>

                    <QuizTextWithKatexAndRandom content={quizState.text} />

                    {!!quiz?.imageurl ? (
                        <Card.Img variant="top" src={quiz.imageurl} />
                    ) : null}

                    {!!quiz?.sceneType ? <ThreeJSViewer
                        figureType={quiz?.sceneType}
                    /> : null}

                    {!!quiz?.functionGraph ?

                    <JSXFunctionGraph 
                      functionType={quiz.functionType}
                      func={quiz.func}
                     
                    />

                        // <FunctionGraph
                        //     selectedFunction={quiz.functionType}
                        //     func={quiz.func}
                        // />
                        : null}


                    {!!quiz?.JSXGraph ?

                        <PrepareJSXGraph
                            quizTemplate={quiz.JSXGraphType}
                        /> : null}

                    {/* {!!quiz?.laboratoryChart ? <GetChartForQuiz laboratoryChart={quiz.laboratoryChart} /> : null}  */}

                    <ProcessKatex
                        text={quizState.text}
                        className="card-text mb-3 math-text"
                    />




                    {chooseQuizType(quiz)}

                    {/* <CheckAnswer /> */}

                    <QuizFeedback />


                </Card.Body>





            </QuizDispatchContext.Provider>
        </QuizContext.Provider>
    </Card>
}

export default QuizCardWithStorage