import { useState } from 'react';

import { useContext } from "react";
import { QuizContext, QuizDispatchContext } from "./QuizContext";

import { upsertPost } from '../../features/posts/postsSlice';

import { useSelector, useDispatch } from "react-redux";
import { selectApplication } from '../../features/application/applicationSlice';

import { updateFirebaseNode, getFirebaseNodeKey } from '../../app/firebase';

/**
 * A custom hook for saving data to Firebase Realtime Database.
 * @returns {object} An object containing the save function, loading state, and error state.
 */


export async function saveTestResult(email, content, result = "", user, avatarUrl = null) {

    let updates = {};
    if (email.length > 6) {

        let ruDate = new Intl.DateTimeFormat("ru", {
            weekday: "short",
            year: "numeric",
            month: "short",
            day: "numeric",
            hour: "numeric",
            minute: "numeric",
        }).format(new Date());

        let userEmail = email.replace(/[^a-zA-Z0-9]/g, "_")
        let idPost = getFirebaseNodeKey("usersCraft/" + userEmail + "/posts");
        let currentDay = new Intl.DateTimeFormat("en", {
            weekday: "short",
            year: "numeric",
            month: "short",
            day: "numeric",
        })
            .format(new Date())
            .replace(/[^a-zA-Z0-9]/g, "_");

        let postObject = {
            id: idPost, //Math.floor(Math.random() * 1001),
            title: document?.title + " попытка теста от " + ruDate + " " + result,
            theme: "Контрольные тесты",
            answer: "",
            comment: "",
            type: "html",
            content: content,
            quizString: "",
            deleted: false,
            email: email,
            user: user,
            avatarUrl: !!avatarUrl ? avatarUrl : "https://econolabs.github.io/freelancer.jpg",
            date: new Intl.DateTimeFormat("ru", {
                weekday: "short",
                year: "numeric",
                month: "short",
                day: "numeric",
                hour: "numeric",
                minute: "numeric",
            }).format(new Date()), //Date().toJSON()
        };

        let currentDayObject = {
            id: idPost,
            title: document?.title + " попытка теста от " + ruDate + " " + result,
            theme: "Контрольные тесты",
            email: email,
            user: user,
            type: "html",
            avatarUrl: !!avatarUrl ? avatarUrl : "https://econolabs.github.io/freelancer.jpg",
            timestamp: +Date.now(),
        };

        //  dispatch(upsertPost(postObject));

        updates["/usersCraft/" + userEmail + "/posts/" + idPost] = postObject;
        updates[
            "/currentDay/" + currentDay + "/posts/" + idPost
        ] = currentDayObject;

        updateFirebaseNode(updates);
    }

}

export async function saveQuizResult({
    email = "temp@temp.com",
    title,
    theme,
    hint,
    calculatedAnswer = "",
    processedText = "",
    user, avatarUrl = "https://econolabs.github.io/anonymous.webp"
}) {

    let updates = {};
    if (email.length > 6) {
        let userEmail = email.replace(/[^a-zA-Z0-9]/g, "_")
        let idPost = getFirebaseNodeKey("usersCraft/" + userEmail + "/posts");
        let currentDay = new Intl.DateTimeFormat("en", {
            weekday: "short",
            year: "numeric",
            month: "short",
            day: "numeric",
        })
            .format(new Date())
            .replace(/[^a-zA-Z0-9]/g, "_");

        let postObject = {
            id: idPost, //Math.floor(Math.random() * 1001),
            title: title,
            theme: theme,
            answer: calculatedAnswer,
            comment: !!hint ? hint : title + " (" + theme + ")",
            type: "spreadsheet",
            content: {},
            quizString: processedText,
            deleted: false,
            email: email,
            user: user,
            avatarUrl: !!avatarUrl ? avatarUrl : "https://econolabs.github.io/freelancer.jpg",
            date: new Intl.DateTimeFormat("ru", {
                weekday: "short",
                year: "numeric",
                month: "short",
                day: "numeric",
                hour: "numeric",
                minute: "numeric",
            }).format(new Date()), //Date().toJSON()
        };

        let currentDayObject = {
            id: idPost,
            title: title,
            theme: theme,
            email: email,
            user: user,
            avatarUrl: !!avatarUrl ? avatarUrl : "https://econolabs.github.io/freelancer.jpg",
            timestamp: +Date.now(),
        };

        //  dispatch(upsertPost(postObject));

        updates["/usersCraft/" + userEmail + "/posts/" + idPost] = postObject;
        updates[
            "/currentDay/" + currentDay + "/posts/" + idPost
        ] = currentDayObject;

        await updateFirebaseNode(updates);
    }

}

const useSaveRealtimeDb = () => {
    const globalDispatch = useDispatch();
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState(null);
    let { title, theme, hint, isExam, id, userAnswer, selectedAnswers, randomValue } = useContext(QuizContext);
    const { email, user, avatarUrl } = useSelector(selectApplication);

    /**
     * Saves data to a specified path in the Realtime Database.
    * @returns {Promise<void>}
     */
    const saveData = async (userValue) => {
        setLoading(true);
        setError(null);

        // let updates = {};
        // updates["/temp"] = { temp: "temp" }

        if (isExam) {
            console.log(id)
            globalDispatch(
                upsertPost({
                    quizId: id,
                    id: id,
                    timestamp: Date.now(),
                    userValue: selectedAnswers.length > 0 ? selectedAnswers : userValue ,
                    randomValue
                }))
        }


        try {
            saveQuizResult({
                title, theme, hint,
                email, user, avatarUrl,
                calculatedAnswer: "",
                processedText: ""
            })
            //    await updateFirebaseNode(updates); // Use set() to write or replace data at a specific path
            console.log(id, title, theme, isExam)
        } catch (err) {
            setError(err);
        } finally {
            setLoading(false);
        }
    };

    return { saveData, loading, error };
};

export default useSaveRealtimeDb